class HandleBrandListSection {
  constructor(mainSection) {
    this.mainSection = mainSection
    this.setup()

    this.displayBtnAllBrands()
    this.enableHandlersControlBrandsLists()
  }

  setup() {
    this.allCarList = document.getElementById('all_cars')
    this.newCarList = document.getElementById('new_cars')
    this.usedCarList = document.getElementById('used_cars')
    this.allMotorcyclesList = document.getElementById('all_motorcycles')
    this.newMotorcyclesList = document.getElementById('new_motorcycles')
    this.usedMotorcyclesList = document.getElementById('used_motorcycles')
    this.allCTList = document.getElementById('all_commercial_transports')
    this.newCTList = document.getElementById('new_commercial_transports')
    this.usedCTList = document.getElementById('used_commercial_transports')
    this.currentBrandList = this.allCarList

    Array.prototype.slice.apply([
      this.allCarList,
      this.newCarList,
      this.usedCarList,
      this.allMotorcyclesList,
      this.newMotorcyclesList,
      this.usedMotorcyclesList,
      this.allCTList,
      this.newCTList,
      this.usedCTList,
    ]).forEach(element => {
      const shortList = element.querySelector('.short_brand_list')
      const fullList = element.querySelector('.brand_list')
      const lastChildElement = shortList.lastElementChild
      const countBrands = this.isMobile() ? 10 : 20
      const showAllBrandsButton = element.querySelector('.js-f-show-all-brands')

      if (!lastChildElement) return
      const targetEl = lastChildElement.lastElementChild

      if ((fullList.childElementCount > countBrands) && targetEl) targetEl.replaceWith(showAllBrandsButton)
    })

    document.getElementById('brands_section').classList.add('is-ready')
  }

  isMobile() {
    return window.innerWidth <= 760
  }

  fetchStateFilters(elements) {
    return Array.prototype.slice.call(elements).map(el => el.value).join('_')
  }

  displayBtnAllBrands() {
    let countBrands = this.isMobile() ? 10 : 20
    let linkToCatalog = this.currentBrandList.getElementsByClassName('link_to_catalog')[0]
    let btnShowBrands = this.currentBrandList.getElementsByClassName('js-show-all-brands')[0]
    let fullBrandsList = this.currentBrandList.getElementsByClassName('brand_list')[0]
    
    // TODO: В этом условии есть проблема если в allCarList коротких брэндов < 20 и при этом полный список брэндов > короткого списка брэндов
    if (btnShowBrands && fullBrandsList.childElementCount > countBrands) {
      btnShowBrands.style.display = 'block'
      linkToCatalog.style.display = 'none'
      if (this.isMobile() && btnShowBrands) this.mainSection.style.marginBottom = '0px'
    } else {
      if (btnShowBrands) btnShowBrands.style.display = 'none'
      linkToCatalog.style.display = 'block'
      if (this.isMobile()) this.mainSection.style.marginBottom = '60px'
    }
  }

  enableHandlersControlBrandsLists() {
    this.mainSection.getElementsByClassName('brand_control')[0].addEventListener('click', event => {
      if (event.target.nodeName == 'INPUT') {
        this.updateBrandList()
        this.displayBtnAllBrands()
      }
    })

    this.mainSection.getElementsByClassName('brand_wrap')[0].addEventListener('click', event => {
      if (event.target.classList.contains('js-btn-all-brands')) {
        this.removeBtnAndOpenBrandList(event.target.parentElement)
      }
    })
  }

  removeBtnAndOpenBrandList(btn) {
    btn.remove()
    this.currentBrandList.getElementsByClassName('short_brand_list')[0].classList.add('hidden')
    this.currentBrandList.getElementsByClassName('brand_list')[0].classList.remove('hidden')

    this.currentBrandList.getElementsByClassName('brand_list')[0].style.maxHeight = 'none'
    this.currentBrandList.getElementsByClassName('brand_list')[0].style.overflow = 'auto'
    this.currentBrandList.getElementsByClassName('link_to_catalog')[0].style.display = 'block'

    this.sortBrandList(this.currentBrandList.getElementsByClassName('brand_list')[0])
    if (this.isMobile()) this.mainSection.style.marginBottom = '60px'
  }

  sortBrandList(list) {
    const items = list.getElementsByTagName("li")
    let brands = [...items]

    brands.sort(function(a, b) {
      return a.textContent.localeCompare(b.textContent)
    })

    list.innerHTML = brands.map(function(brand) {
      return brand.outerHTML
    }).join("");
  }

  updateBrandList() {
    let statesFilters = this.fetchStateFilters(this.mainSection.querySelectorAll('input[type=radio]:checked'))

    this.currentBrandList.classList.add('hidden')

    switch (statesFilters) {
      case 'all_car':
        this.allCarList.classList.remove('hidden')
        this.currentBrandList = this.allCarList
        break;
      case 'new_car':
        this.newCarList.classList.remove('hidden')
        this.currentBrandList = this.newCarList
        break;
      case 'used_car':
        this.usedCarList.classList.remove('hidden')
        this.currentBrandList = this.usedCarList
        break;
      case 'all_motorcycle':
        this.allMotorcyclesList.classList.remove('hidden')
        this.currentBrandList = this.allMotorcyclesList
        break;
      case 'new_motorcycle':
        this.newMotorcyclesList.classList.remove('hidden')
        this.currentBrandList = this.newMotorcyclesList
        break;
      case 'used_motorcycle':
        this.usedMotorcyclesList.classList.remove('hidden')
        this.currentBrandList = this.usedMotorcyclesList
        break;
      case 'all_commercial_transport':
        this.allCTList.classList.remove('hidden')
        this.currentBrandList = this.allCTList
        break;
      case 'new_commercial_transport':
        this.newCTList.classList.remove('hidden')
        this.currentBrandList = this.newCTList
        break;
      case 'used_commercial_transport':
        this.usedCTList.classList.remove('hidden')
        this.currentBrandList = this.usedCTList
        break;
      default:
        console.log('Brand`s list undefined')
    }
  }
}

