$(document).ready(() => {
  const $wrapper = $('.online-order-request-form-wrapper')

  if ($wrapper.length) {
    const $radioButtons = $wrapper.find('.radio_buttons')
    const $radioInput = $radioButtons.find('input[type=radio]')
    const $userAddress = $('.page-service__request-form_user-address')
    const $distributionPoint = $('.page-service__request-form_distribution-point')
    const $onlineOrderCityInput = $wrapper.find('.js-online-order-city input')
    const $onlineOrderAddressInput = $wrapper.find('.js-online-order-address input')

    $onlineOrderCityInput.on('keyup', function(event) {
      const isDisabled = event.target.value.length <= 2

      $onlineOrderAddressInput.prop('disabled', isDisabled)
    })

    // set deafult value
    const $homeDeliveryRadio = $('input[value=distribution_point]')
    $homeDeliveryRadio.attr('checked', true)
    $homeDeliveryRadio.parent().addClass('radio_buttons__label_checked')
    $userAddress.hide()

    // radio checking
    $radioInput.each((i, item) => {
      $(item).on('change', function() {
        const $radioLabel = $(item).parent()
        const $allLabels = $radioLabel.parent().find('label')

        $allLabels.removeClass('radio_buttons__label_checked')
        $radioLabel.addClass('radio_buttons__label_checked')

        if ($(item).val() === 'home_delivery') {
          $userAddress.show()
          $distributionPoint.hide()
        } else if ($(item).val() === 'distribution_point') {
          $userAddress.hide()
          $distributionPoint.show()
        }
      })
    })

    //  distribution dealer select
    // const $distributionPoint = $('.page-service__request-form_distribution-point')
    const $distributionPointCitySelect = $distributionPoint.find('.city_select').find('select')
    const $distributionPointCityFakeSelect = $distributionPoint.find('.city_select').find('.select__container')
    const $dealerSelect = $distributionPoint.find('.js-dealer-select')
    const $distributionPointDealerSelect = $distributionPoint.find('.dealer_select').find('select')
    const $distributionPointDealerFakeSelect = $distributionPoint.find('.dealer_select').find('.select__container')

    const $distributionPointCitySelectOptions = $distributionPoint.find('.city_select').find('li.select__option')
    const $distributionPointDealerSelectOptions = $distributionPoint.find('.dealer_select').find('li.select__option')

    function set_dealers_in_distribution_dealer_select(city_id) {
      $distributionPointDealerSelectOptions.each((i, item) => {
        const dealer_id = $(item).data('value')
        const original_option = $distributionPointDealerSelect.find(`option[value=${dealer_id}]`)

        if ($(item).data('city-id') == city_id){
          $(item).show()
          original_option.show()
        }else{
          $(item).hide()
          original_option.hide()
        }
      })
    }

    function drop_value_in_distribution_dealer_select() {
      var placeholder = document.createElement('div');
      placeholder.className = "placeholder"
      placeholder.innerHTML = $distributionPointDealerFakeSelect.find('.select__input').data('placeholder')

      $distributionPointDealerFakeSelect.find('.select__input').html(placeholder)
      $distributionPointDealerSelect.val(-1)
    }

    function set_dealer_by_id(dealer_id) {
      const city_id = $distributionPointDealerSelectOptions.filter(`[data-value=${dealer_id}]`).data('city-id')
      const city_html = $distributionPointCitySelectOptions.filter(`[data-value=${city_id}]`).html()

      const dealer_html = $distributionPointDealerSelectOptions.filter(`[data-value=${dealer_id}]`).html()

      $distributionPointDealerFakeSelect.find('.select__input').html(dealer_html)
      $distributionPointCityFakeSelect.find('.select__input').html(city_html)

      $distributionPointCitySelect.val(city_id)
      set_dealers_in_distribution_dealer_select(city_id)
      $distributionPointDealerSelect.val(dealer_id)
    }

    set_dealers_in_distribution_dealer_select($distributionPointCitySelect.val())

    $($distributionPointCitySelectOptions).on('click', function() {
      $dealerSelect.addClass('is-visible')

      set_dealers_in_distribution_dealer_select($(this).data('value'))

      drop_value_in_distribution_dealer_select()
    })

    $(document).on('click', '.result-link a', function() {
      dealer_id = $(this).closest('li').data('vehicle-dealer-id')

      set_dealer_by_id(dealer_id)
    })
  }
});
