$(document).ready(() => {
  // Реализация формы расчета конечной суммы оплаты с комиссией
  //
  // Все суммы на странице начиная с "10 000" форматируются пробелами

  // Поля расчета платежа
  const $price = $('.js-success-page-online-payment-price');
  const $fee = $('.js-success-page-online-payment-price-fee');
  const $total = $('.js-success-page-online-payment-price-total');
  const $payment_link = $('.js-success-page-online-payment-price-submit');

  // Комиссия банка
  const fee_size = 1.45; // 1.45%
  // Если оригинальная комиссия X, тогда введенная сумма занимает в
  // общей сумме Y; Y + X == 100%
  const original_price_percent = 100 - fee_size;

  // Форматирование суммы оплаты
  // 1000 => "1000"
  // 10000 => "10 000"
  // 12000500.50 => "12 000 500.50"
  const formatValue = function(value) {
    const val = value.toString();
    const splitted = val.split('.'); // разделим "100.42" на ["100", "42"]
    const whole = splitted[0]; // целая часть цены
    const remainder = splitted[1] || ''; // копейки

    if (whole.length < 5) {
      return val;
    }

    const formated = whole.split('').reverse().reduce(function(acc, current, index) {
      acc.push(current);

      if ((index + 1) % 3 === 0) {
        acc.push(' ');
      };

      return acc;
    }, []).reverse().join('');

    if (remainder.length > 0) {
      return [formated, '.', remainder].join('');
    } else {
      return formated;
    }
  }

  // Слушаем события ввода нового символа в поле цены
  $price.on('keyup', function(data) {
    // Оставляем только числа из данных введенных в поле цены
    const original_price = parseInt(data.target.value.replace(/[^0-9]/g, '')) || 0;

    // Если пользователь очистил поле, очищаем поля комиссии и
    // финальной цены
    if (original_price === 0) {
      $fee.text(0);
      $total.text(0);
      return;
    }

    // Рассчитываем общую сумму к оплате с расчетом комиссии, приводим
    // результат к копейкам
    const original_price_with_fee = Number((original_price / original_price_percent * 100).toFixed(2));
    // Рассчитываем сумму комиссии
    const fee = Number((original_price_with_fee - original_price).toFixed(2));

    // Обновляем значения комиссии и общей суммы оплаты
    $fee.text( formatValue(fee) );
    $total.text( formatValue(original_price_with_fee) );

    // Форматируем введенное в форму значение для расставления
    // пробелов
    const formated_price = formatValue(original_price);
    // Обновляем только если значения изменилось для работы
    // перемещения курсора стрелками
    if ($price.val() !== formated_price) {
      $price.val(formated_price);
    }

    // Обновить ссылку на страницу платежа
    updatePaymentLink(original_price_with_fee);
  });

  // Обновить ссылку на страницу платежа
  const updatePaymentLink = function(price) {
    const amount = {
      amount: price.toString()
    };
    // подставим сумму платежа в базовую ссылку
    const payment_url_with_amount =
          `${$payment_link.attr('data-base-url')}&def=${encodeURI(JSON.stringify(amount))}`;

    $payment_link.attr("href", payment_url_with_amount);
  }
});
/**
 * Восстанавливает из window.Catalog
 * переменную в массив параметров для запроса
 * если в исходном массиве этого параметра нет
 *
 * @param {string} fieldName - Имя поля параметра, которое нужно восстановить
 * @param {string} globalField - Имя поля в window.Catalog из которого восстановить
 * @param {object[]} sourceArray - Исходный массив параметров
 * @returns {void}
 */
function restoreFieldFromGlobal(fieldName, globalField, sourceArray) {
  if (!sourceArray.some((param) => param.name === fieldName))
    sourceArray.push({
      name: fieldName,
      value: window.Catalog[globalField],
    });
}

// FIXME функция вызывается при изменении 3х форм в мобильной версии (форма с брендом
// и моделью, форма в хедере, и доп. форма), пытаясь угадать, что именно ей
// сериализовывать и делает это довольно плохо
function mkp_filter_vehicle(top_select, only_dealers, clear_list = false, make_request = true, without_rerender_generation = false) {
  var near_form
  var query_params
  var main_form_params
  var mkp_form_params
  var dealers_form = $('#sort_dealers_form')
  var previous_params

  // Вызов из формы хедера на мобильных
  if (top_select.attr('id') === 'sort_dealers_form') {
    // Забираем параметры с предыдущего фетча и формы хедера
    near_form = $('#mkp_mobile_form')
    previous_params = near_form.serializeArray()
    dealers_form_params = dealers_form.serialize()

    if (make_request)
      return $.get(
        near_form.attr('action'),
        $.param(previous_params) + '&' + dealers_form_params
      )
  } else {
    near_form = top_select.closest('form')
  }

  var tab_pane = ''

  if (only_dealers && make_request) {
    dealers_form_params = dealers_form.serialize()

    return $.get(
      near_form.attr('action'),
      'id=' + $("aside input[name='id']").val() + '&' + dealers_form_params
    )
  }

  // Проверяем, нужно ли нам учитывать доп. мобильные фильтры. (Нужно если
  // вызов идет из формы с доп фильтрами)
  if (near_form.attr('id') == 'mkp_mobile_form') {
    if (top_select.hasClass('tab-pane')) {
      tab_pane = top_select.attr('id')
    } else {
      tab_pane = $('#mkp_mobile_form li.active').find('a').attr('aria-controls')
    }

    mkp_form_params = $(
      '#mkp_mobile_form #' + tab_pane + ' :input'
    ).serializeArray()

    query_params =
      $.param(mkp_form_params) +
      '&' +
      dealers_form.serialize() +
      '&update_options=true'

    dealers_form.data('previous_params', mkp_form_params)
    if (make_request) return $.get(near_form.attr('action'), query_params)
  } else {
    // Вызов из основной формы на мобильных устройствах
    // Или из основой или хедера на десктопе
    // Или из опционально появляющейся секции с программами, которая находится
    // в основном блоке на десктопе и в доп. фильтрах на мобильных
    if (top_select.attr('name') !== 'programs[]') {
      mkp_reset_additional_filters($('#mkp_mobile_form'))
    }

    main_form_params = near_form.serializeArray()

    const paramsToBeRestored = [
      {
        local: 'vehicle_brand',
        global: 'brand_id',
      },
      {
        local: 'vehicle_model',
        global: 'model_id',
      },
      /**
       * Сюда можно добавить прочие переменные
       * которые теряются при пустой выдаче
       */
    ]

    if (!clear_list)
      paramsToBeRestored.forEach(({ local, global }) => {
        restoreFieldFromGlobal(local, global, main_form_params)
      })

    main_form_params.push({
      name: 'without_rerender_generation',
      value: without_rerender_generation,
    })

    query_params = $.param(main_form_params) + '&' + dealers_form.serialize()

    dealers_form.data('previous_params', main_form_params)

    if (make_request) return $.get(near_form.attr('action'), query_params)
  }

    let filterResult = {}

    $('.filter__wrapper').each(function () {
      $(this)
        .find('.select__label')
        .each(function () {
          const labelText = $.trim($(this).text())

          const inputValue = $.trim($(this).next('.select__input').text())

          const excludeValues = [
            'любой',
            'любая',
            'любое',
            'от',
            'до',
            'все марки',
            'все модели',
          ]
          if (
            !excludeValues.includes(inputValue.toLowerCase()) &&
            inputValue !== ''
          ) {
            vehicleDataStore.setFilterData(labelText, inputValue);

            filterResult[labelText] = inputValue
          }
        })
    })
}

function storeFilterData() {
  if ($("aside.cars__sidebar").is(":visible")) {
    mkp_filter_vehicle($("aside .filter__wrapper"), false, false, false);
    return
  }

  if ($("#mkp_mobile_form").is(":visible")) {
    mkp_filter_vehicle($("#mkp_mobile_form #" + pane), false, false, false);
  } else {
    if ($("header #brands").is(":visible")) {
      mkp_filter_vehicle($("#sort_dealers_form"), false, false, false);
    } else {

      mkp_filter_vehicle($("#mkp_mobile_form #" + pane), true, false, false);
    }
  }
}

function redraw_search_result(pane, clear_list = false) {
  if (pane === undefined) pane = "cars-pane";

  if ($("aside.cars__sidebar").is(":visible")) {
    mkp_filter_vehicle($("aside .filter__wrapper"), false, clear_list);
    return;
  }

  if ($("#mkp_mobile_form").is(":visible")) {
    mkp_filter_vehicle($("#mkp_mobile_form #" + pane), false, clear_list);
  } else {
    if ($("header #brands").is(":visible")) {
      // Вызов из хедера мобильной формы (город/салон/сортировка)
      mkp_filter_vehicle($("#sort_dealers_form"), false, clear_list);
    } else {
      mkp_filter_vehicle($("#mkp_mobile_form #" + pane), true, clear_list);
    }
  }
}

function smart_catalog_set_models(vehicle_type, selected_model_id) {
  if ($("aside.cars__sidebar").is(":visible")) {
    // Если десктопные фильтры
    catalog_set_models($("aside #brands"), selected_model_id, true);
    if (vehicle_type == "Car")
      catalog_set_generations($("aside #models"), selected_model_id, true);
  }

  if ($("header #brands").is(":visible")) {
    // Если мобильные фильтры
    catalog_set_models($("header  #brands"), selected_model_id, true);

    if (vehicle_type == "Car") {
      catalog_set_models(
        $("#mkp_mobile_form #cars-pane .select[data-field='cars_brands']"),
        selected_model_id,
        true
      );
      catalog_set_generations(
        $("#mkp_mobile_form #cars-pane .select[data-field='cars_models']"),
        selected_model_id,
        true
      );
    }

    if (vehicle_type == "CommercialTransport") {
      catalog_set_models(
        $("#mkp_mobile_form #commercial-pane"),
        selected_model_id,
        true
      );
    }

    if (vehicle_type == "Motorcycle") {
      catalog_set_models(
        $("#mkp_mobile_form #moto-pane"),
        selected_model_id,
        true
      );
    }
  }
}

