function resetSelectFilter(target, clear_list, the_text) {
  var target_select = target.find("select");
  var target_ul = target.find("ul");

  target.addClass("select_disabled");
  target_select.attr("disabled", true);

  if (clear_list) {
    target_ul.html("");
    target_select.html("");
  }

  target.find(".select__input").text(the_text);

  if (!clear_list) {
    target.removeClass("select_disabled");
    target_select.removeAttr("disabled");
  }

  value = target_select.find("option").first().val();

  target.find(".select__input").data("selected", value);

  resetHiddenFilter(target_select, value);
}

function resetSelectFiltersByClass(top_form, class_name, clear_list, the_text) {
  var targets = top_form.find(class_name);
  targets.each(function () {
    resetSelectFilter($(this), clear_list, the_text);
  });
}

function mkp_reset_select(top_form, select_id, clear_list, the_text) {
  resetSelectFilter(top_form.find(select_id), clear_list, the_text);
}

function mkp_reset_switch_filter(filterName) {
  filter = $("input[name='" + filterName + "']");
  filter.prop("checked", false);
  filter.val(false);
}

function mkp_reset_switch_filter_by_id(filterId) {
  filter = $("input[id='" + filterId + "']");
  filter.prop("checked", false);
}

const categoriesMap = {
  '/cars': 'Легковые | Все',
  '/new/cars': 'Легковые | Новые',
  '/used/cars': 'Легковые | С пробегом',
  '/commercial_transports': 'Комтранс | Все',
  '/new/commercial_transports': 'Комтранс | Новые',
  '/used/commercial_transports': 'Комтранс | С пробегом',
  '/motorcycles': 'Мотоцыклы | Все',
  '/new/motorcycles': 'Мотоцыклы | Новые',
  '/used/motorcycles': 'Мотоцыклы | С пробегом'
};

function setCategoryFromUrl(url) {
  Object.keys(categoriesMap).forEach((key) => {
    if (url.includes(key)) {
      vehicleDataStore.setFilterData('category', categoriesMap[key]);
    }
  });
}

function stripUnits(value) {
  return value.replace(/[^0-9]/g, '')
}

function gatherFilterData(mainKey, value, secondaryKeySuffix) {
  const strippedValue = stripUnits(value)
  let existingValue = vehicleDataStore.getFilterData()[mainKey] || '';

  if (secondaryKeySuffix === '_от') {
    if (existingValue.includes(',')) {
      const [, after] = existingValue.split(',')
      existingValue = strippedValue + ',' + after
    } else {
      existingValue = strippedValue + ','
    }
  } else if (secondaryKeySuffix === '_до') {
    if (existingValue.includes(',')) {
      const [before] = existingValue.split(',')
      existingValue = before + ',' + strippedValue
    } else {
      existingValue = ',' + strippedValue
    }
  } else {
    existingValue = value
  }

  vehicleDataStore.setFilterData(mainKey, existingValue);
  setCategoryFromUrl(window.location.pathname)
  sendFiltersToGtm('use_filters', vehicleDataStore.getFilterData())
}

function initCatalogEventListeners() {
  $('#brands.select').on('selected', function () {
    catalog_set_models($(this))
    var top_form = $(this).closest('form')
    brand = $(this).find('.select__container .select__input').text()
    brand_id = $(this)
      .find('.select__container .select__input')
      .data('selected')
    slug = $(this).find('select > option:selected').data('slug')
    var state_btn = $('.vehicle_use_state.filter-white_btn').find('.active')[0]
    if (state_btn) Catalog.setUseState(state_btn.dataset.useState)
    Catalog.setBrand(brand, slug, brand_id)
    Catalog.updateHistoryAndTitle()
    mkp_reset_additional_filters(top_form)
    mkp_filter_vehicle($(this), false)
    gatherFilterData('Бренд', brand)
  })

  $('#models.select').on('selected', function () {
    catalog_set_generations(
      $(this),
      $(this).find('.select__container .select__input').data('selected'),
      false
    )
    var top_form = $(this).closest('form')
    mkp_reset_additional_filters(top_form)
    mkp_filter_vehicle($(this), false, false, true, true)
    model = $(this).find('.select__container .select__input').text()
    slug = $(this).find('select > :selected').data('slug')
    model_id = $(this)
      .find('.select__container .select__input')
      .data('selected')
    Catalog.setModel(model, slug, model_id)
    Catalog.updateHistoryAndTitle()
    gatherFilterData('Модель', model)
  })

  $('#generations.select').on('selected', function () {
    input = $(this).find('.select__container .select__input')
    selectedValue = $(this).find('option:selected').attr('value')
    let generation = $(this).find('option:selected').text()
    if (selectedValue == '') {
      input.removeAttr('data-selected')
    }
    mkp_filter_vehicle($(this), false, false, true, true)
    gatherFilterData('Поколение', generation)
  })

  const filterEventHandlers = {
    horsepower_mkp_gte: { key: 'Мощность', valueSuffix: ',' },
    horsepower_mkp_lte: { key: 'Мощность', valuePrefix: ',' },
    year_mkp_gte: { key: 'Год выпуска', valueSuffix: ',' },
    year_mkp_lte: { key: 'Год выпуска', valuePrefix: ',' },
    price_mkp_gte: { key: 'Цена', valueSuffix: ',' },
    price_mkp_lte: { key: 'Цена', valuePrefix: ',' },
  }

  $('.select:not(#brands, #sort_type, #generations, #models)').on(
    'selected',
    function () {
      let key = $(this).find('.select__label').text().trim()
      let value = $(this).find('.select__input').text().trim()
      const eventId = $(this).attr('id')

      if (filterEventHandlers[eventId]) {
        key = filterEventHandlers[eventId].key
      }

      if (eventId.includes('horsepower_mkp_gte')) {
        gatherFilterData('Мощность', value, '_от')
      } else if (eventId.includes('horsepower_mkp_lte')) {
        gatherFilterData('Мощность', value, '_до')
      } else if (eventId.includes('year_mkp_gte')) {
        gatherFilterData('Год выпуска', value, '_от')
      } else if (eventId.includes('year_mkp_lte')) {
        gatherFilterData('Год выпуска', value, '_до')
      } else if (eventId.includes('price_mkp_gte')) {
        gatherFilterData('Цена', value, '_от')
      } else if (eventId.includes('price_mkp_lte')) {
        gatherFilterData('Цена', value, '_до')
      } else {
        gatherFilterData(key, value)
      }

      mkp_filter_vehicle($(this), false)
    }
  )

  $('#sort_type.select').on('selected', function (event) {
    var option = $(event.originalEvent.detail.elem)

    var selectedSort =
      "option[value='" + $(this).find('.select__hidden').val() + "']"
    if (option.data('direction'))
      selectedSort += "[direction='" + option.data('direction') + "']"
    var hidden_sort = $(this).find('.select__hidden').find(selectedSort)
    hidden_sort.prop('selected', 'selected')
    $(".sort-dest input[name='sort_direction']").val(option.data('direction'))
    redraw_search_result()
  })

  $('input.switch__input').on('change', function () {
    // check buttons
    if ($(this).prop('checked')) auto_filter($(this))

    mkp_filter_vehicle($(this), false)
  })

  $('#reset-form, #reset_form_mobile').on('click', function () {
    var top_form = $(this).closest('form')

    Catalog.setModel(null, null, null)
    const carTypeUrl = window.location.pathname.split(/\//)[1]
    window.history.pushState(null, null, '/' + carTypeUrl + '/')

    reset_mobile_short_filters()
    mkp_reset_main_filters(top_form)
    mkp_reset_additional_filters(top_form)
    mkp_reset_dealers()
    mkp_reset_cities()
    mkp_reset_sort()

    redraw_search_result(null, true)
  })

  $('.select').on('change', '.checkbox__input', function () {
    // dealers
    var thisSelect = $(this).closest('.select')
    var hiddenSelect = thisSelect.find('.select__hidden').prop('name')
    var selectName = hiddenSelect ? hiddenSelect.split('_')[0] : ''

    var str = ''

    thisSelect
      .find('.checkbox__input')
      .filter(':checked')
      .each(function () {
        str += $(this).data('value') + ','
      })
    if (str.length > 0) str = str.substr(0, str.length - 1)
    if (selectName.length > 0) $('#' + selectName).val(str)
    redraw_search_result()
  })

  $('#sort-dest').on('change', function () {
    if ($(this).prop('checked')) {
      $('#sort_direction').val('asc')
    } else {
      $('#sort_direction').val('desc')
    }
    redraw_search_result()
  })

  // Категории прав
  $("input.radio__input[type='checkbox']").on('change', function () {
    var thisSelect = $(this).closest('.filter__line')
    var str = ''

    thisSelect
      .find('.radio__input')
      .filter(':checked')
      .each(function () {
        str += $(this).data('value') + ','
      })

    if (str.length > 0) str = str.substr(0, str.length - 1)

    thisSelect.find('#driving_license_category').val(str)
    redraw_search_result()
  })
}

