function transferStickers() {
  var cars = $(".cars-list__item");
  $(".stickers-transfered").removeClass("stickers-transfered");
  for (var i = 0; i < cars.length; i++) {
    var car = $(cars[i]);
    link = car.find(".card-info__link");
    title = car.find(".card-info__title");
    icon = car.find(".card-info__icon");
    title_pos = title.position().top;
    icon_pos = (icon.length > 0 && icon.position().top) || 0;
    if (icon_pos - title_pos > 5) {
      link.addClass("stickers-transfered");
    }
  }
}

function debounce(func, time) {
  var time = time || 100; // 100 by default if no param
  var timer;
  return function (event) {
    if (timer) clearTimeout(timer);
    timer = setTimeout(func, time, event);
  };
}

function resizeEnded() {
  transferStickers();
}

$(window).on("resize", debounce(resizeEnded, 600));
