const DEFAULT_BASE_URL = window.location.origin.includes('staging') || window.location.origin.includes('localhost')  ? 'https://devapi.freshauto2.ru' : 'https://mobile.freshauto.ru';

const CREDIT_API_URL =  window.location.origin.includes('staging') || window.location.origin.includes('localhost')  ? 'https://credit.staging.freshauto.dev' : 'https://credit.freshauto.ru';

function createQueryString(params) {
  return Object.keys(params).length
    ? '?' + new URLSearchParams(params).toString()
    : ''
}

function createRequest(method, headers = {}, baseUrl = DEFAULT_BASE_URL) {
  if(!baseUrl) console.warn('No URL provided. All requests will be sent on the origin.')
  return async function (url, data = {}, multipart = '') {
    try {
      let fullUrl = baseUrl + url
      let fetchOptions = {
        method: method,
        headers: multipart.length
          ? {
              'Content-Type': 'application/json',
              accept: 'application/json',
              ...headers,
            }
          : headers,
      }

      if (multipart.length) {
        const formData = new FormData()
        for (const name in data) {
          formData.append(`${multipart}[${name}]`, data[name])
        }
        fetchOptions.body = formData
      } else if (method === 'GET') {
        fullUrl += createQueryString(data)
      } else {
        fetchOptions.body = typeof data === 'string' ? data : JSON.stringify(data)
      }
      const response = await fetch(fullUrl, fetchOptions)

      if (!response.ok) {
        const errorText = await response.text();
        const error = new Error(`Request failed with status ${response.status}`);
        error.status = response.status;
        error.responseText = errorText;
        throw error;
      }

      const responseData = await response.text();
      try {
        const data = JSON.parse(responseData);
        return data;
      } catch(err) {
        return responseData;
      }
    } catch (error) {
      console.error('API call failed:', error)
      throw error
    }
  }
}

const customRequest = {
  get: createRequest('GET'),
  creditApi: createRequest('GET', { accept: "application/json" }, CREDIT_API_URL),
  post: createRequest('POST'),
  crmPost: createRequest('POST'),
  postMultipart: createRequest('POST', {}, DEFAULT_BASE_URL),
};
const FilterWidget = {
  init(element) {
    this.state = {
      brandId: null,
      brandSlug: null,
      modelId: null,
      modelSlug: null,
    }
    this.$el = $(element)
    this.brands = this.prepareBrands()
    this.$brandSelect = this.$el.find('.js-f-filter-widget-brands select')
    this.$modelSelect = this.$el.find('.js-f-filter-widget-models select')
    this.$button = this.$el.find('.js-f-filter-widget-button')
    this.$buttonCount = this.$button.find('.count')

    this.initSelect2(this.$brandSelect, this.brands, 'Марка', false)
    this.initSelect2(this.$modelSelect, [], 'Модель', true)
    this.bindEvents()
  },

  prepareBrands() {
    const brands = this.$el.data('brands')
    this.$el.removeAttr('data-brands')

    return brands.map(brand => {
      return {
        id: JSON.stringify({ id: brand.id, count: brand.count, slug: brand.slug }),
        text: brand.text,
      }
    })
  },

  buildUrl() {
    const { brandSlug, modelSlug } = this.state
    const brandModelPair = ['/cars', brandSlug, modelSlug].filter(item => item).join('/') + '/'
    let queryParams = []

    queryParams = queryParams.join('&')

    return [brandModelPair, queryParams].filter(item => item).join('?')
  },

  // eslint-disable-next-line max-lines-per-function
  bindEvents() {
    this.$brandSelect.on('change', event => {
      const { id: brandId, slug } = JSON.parse(event.target.value)

      this.getModels(brandId)
        .then(models => {
          this.replaceModelOptions(models)
          this.state.brandId = brandId
          this.state.brandSlug = slug
          this.state.modelId = null
          this.state.modelSlug = null

          return this.getCount()
        })
        .then(count => {
          this.setCount(count)
          this.buildUrl()
        })
    })

    this.$modelSelect.on('change', event => {
      const { id, slug } = JSON.parse(event.target.value)
      this.state.modelId = id
      this.state.modelSlug = slug

      this.getCount()
        .then(count => {
          this.setCount(count)
          this.buildUrl()
        })
    })

    this.$button.on('click', () => {
      if (this.$button.prop('disabled')) return
      window.location.href = this.buildUrl()
    })
  },

  initSelect2(selector, data, placeholder, disabled) {
    selector.select2({
      width: '100%',
      data,
      minimumResultsForSearch: Infinity,
      placeholder,
      disabled,
    })

    selector.val('').trigger('change.select2')
  },

  setCount(count) {
    this.$button.prop('disabled',!count);
    this.$buttonCount.text(count)
  },

  getCount() {
    const pairs = {
      car_brand_id: this.state.brandId,
      car_model_id: this.state.modelId,
    }

    const params = Object.keys(pairs).reduce((prev, key) => {
      return pairs[key] ? { ...prev, [key]: pairs[key] } : prev
    }, {})

    return fetch('/cars/list/?' + new URLSearchParams(params))
      .then(response => response.json())
      .then(response => response.meta.total_count)
  },

  replaceModelOptions(models) {
    const htmlModels = models.reduce((prev, model) => {
      const data = JSON.stringify({ id: model.id, slug: model.slug, count: model.count })
      return prev + `<option value='${data}'>${model.text}</option>`
    }, '')

    if (models.length) {
      this.$modelSelect.prop('disabled', false)
      this.$modelSelect.html(htmlModels)
    }
    else {
      this.$modelSelect.prop('disabled', true)
    }

    this.$modelSelect.val('').trigger('change.select2')
  },

  getModels(brandId) {
    const url = `/cars/${brandId}/vehicle_models_by_brand/`

    return fetch(url, {
      headers: { 'content-type': 'application/json' },
    })
      .then(response => response.json())
      .then(response => {
        return response.vehicle_models.slice(1).map(model => ({
          id: model.id,
          text: model.name,
          slug: model.slug,
          count: model.count,
        }))
      })
  },
}

document.addEventListener('DOMContentLoaded', function() {
  const burgerTrigger = document.querySelector('.js-burger-menu')
  const dropdownMenu = document.querySelector('.js-dropdown-menu')
  const dropdownMenuOverlay = document.querySelector('.js-dropdown-menu-overlay')
  const mobileNav = document.querySelector('.js-f-mobile-nav')
  const isMobile = document.documentElement.classList.contains('mobile')
  const vehiclePage = document.querySelector('.js-f-vehicle')
  const vehicleFixedPlaceholder = document.querySelector('.js-f-vehicle-placeholder-fixed')
  const mobileMenuList = document.querySelector('.f-mobile-nav__items')
  const filterWidget = document.querySelector('.js-f-filter-widget')

  if (filterWidget) FilterWidget.init(filterWidget)

  if (mobileMenuList) {
    mobileMenuList.addEventListener('click', function(event) {
      const target = event.target
      if (target.classList.contains('js-f-mobile-menu-expandable')) {
        const isOpened = target.classList.contains('is-open')
        target.classList[isOpened ? 'remove' : 'add']('is-open')
      }
    })
  }

  if (vehiclePage && isMobile) {
    window.addEventListener('scroll', function () {
      if (window.scrollY > 64) {
        if(vehicleFixedPlaceholder) vehicleFixedPlaceholder.classList.add('is-show')
      }
      else {
        if(vehicleFixedPlaceholder) vehicleFixedPlaceholder.classList.remove('is-show')
      }
    })
  }

  if (isMobile) {
    if (burgerTrigger && mobileNav) {
      burgerTrigger.addEventListener('click', function() {
        mobileNav.classList.add('f-open')
        dropdownMenuOverlay.classList.add('is-open')
        document.body.classList.add('js-mobile_opened')
      })

      dropdownMenuOverlay.addEventListener('click', function() {
        mobileMenuList.querySelectorAll('.js-f-mobile-menu-expandable').forEach(el => el.classList.remove('is-open'))
        mobileNav.classList.remove('mobile-nav_opened')
        dropdownMenuOverlay.classList.remove('is-open')
        document.body.classList.remove('js-mobile_opened')
      })
    }
  }
  else {
    if (burgerTrigger && dropdownMenuOverlay && !mobileNav) {
      let isMenuOpened = false
      dropdownMenuOverlay.addEventListener('click', function () {
        dropdownMenu.classList.remove('is-open')
        dropdownMenuOverlay.classList.remove('is-open')
        burgerTrigger.classList.remove('is-open')
        isMenuOpened = false
      })

      burgerTrigger.addEventListener('click', function() {
        burgerTrigger.classList[isMenuOpened ? 'remove' : 'add']('is-open')
        dropdownMenu.classList[isMenuOpened ? 'remove' : 'add']('is-open')
        dropdownMenuOverlay.classList[isMenuOpened ? 'remove' : 'add']('is-open')
        isMenuOpened = !isMenuOpened
      })
    }
  }
});
