      var url;
      url = [this.use_state, this.type, this.brand_slug, this.model_slug].filter((function(_this) {
        return function(obj) {
          return obj;
        };
      })(this)).join(' ').split(/\s+/).join('/');
      return window.history.pushState(null, null, '/' + url + '/');
