// Правки от Богдана по избранному

$(document).on(
  'click',
  '.card-actions__btn, .mkp_card-actions__btn',
  function () {
    handleFavorite(
      $(this),
      $(this).hasClass('card-actions__add') ? 'POST' : 'DELETE'
    )
  }
)

async function handleFavorite($button, type) {
  if (await authenticateAndLoadUser()) {
    const newText =
      type === 'POST' ? 'Удалить из избранного' : 'Добавить в избранное'
    const iconReplacement = type === 'POST' ? 'plus' : 'check'

    // carousel-item__link
    const parentNode = $button.parent().parent()[0];
    const slugContainer = parentNode.querySelector('.carousel-item__link') || parentNode.querySelector('.card-info__link')

    let split = '/cars/';
    if (slugContainer.href.includes('/commercial_transports/')) {
      split = '/commercial_transports/';
    }
    if (slugContainer.href.includes('/motorcycles/')) {
      split = '/motorcycles/';
    }
    const slug = slugContainer.href.split(split)[1].split('?')[0].replace('/', '');

    const actionFx = iconReplacement !== 'check' ? add_to_favorites : delete_from_favorites;
    actionFx(slug).then(() => {
      $button.toggleClass('card-actions__add card-actions__delete')
      updateButtonVisuals($button, newText, iconReplacement)
    })
  }
}

function updateButtonVisuals($button, newText, iconReplacement) {
  $button.find('span.js-icon-text').text(newText)
  $button.find('.icon_block').toggle()

  const s = $button
    .html()
    .replace(
      new RegExp(iconReplacement, 'g'),
      iconReplacement === 'plus' ? 'check' : 'plus'
    )
  $button.html(s)

  if ($button.hasClass('mkp_card-actions__text')) {
    let $firstBtn = $('.vehicle-header__options')
      .find('.mkp_card-actions__btn')
      .first()
    $firstBtn.html(s)
    $('.vehicle-header__options').find('.mkp_card-actions__text').html(newText)
  }
}

async function authenticateAndLoadUser() {
  const hasAccessToken = getCookie('accessToken')

  if (!hasAccessToken) {
    window.location.assign('/login')
    return false
  }

  return true
}

// Добавление новой логики избранного

const catalogSetFavoritesData = async () => {
  await getFavoritesCars();

  const favData = (new Store('favoritesList')).state.favoritesList;
  const favoritesList = favData ? favData.items.map(item => item.slug) : [];

  let category = ''
  const url = window.location.href;
  const match = url.match(/\/(commercial_transports|cars|motorcycles)(\/|$)/);

  if (match && match[1]) {
     category = match[1];
  }

  Array.from(document.querySelectorAll(".catalog_w .card-actions__delete")).forEach(item => {
    item.classList.toggle('card-actions__delete', false);
    item.classList.toggle('card-actions__add', true);
  })

  favoritesList
    .filter(slug => !!document.querySelector(`.card-info__link[href="/${category}/${slug}/"]`))
    .forEach(slug => {
      const favElement =
        document.querySelector(`.card-info__link[href="/${category}/${slug}/"]`)
          .parentNode
          .parentNode
          .querySelector('.card-actions button')

      favElement.classList.toggle('card-actions__delete', true);
      favElement.classList.toggle('card-actions__add', false);
    })
}

document.addEventListener('DOMContentLoaded', async () => {
  if (document.querySelector(".catalog_w")) {
    catalogSetFavoritesData()

    const cl = (mutation) = debounce(() => catalogSetFavoritesData(), 300);
    const observer = new MutationObserver(function (mutations) {
      mutations.forEach(function (mutation) {
        if (mutation.target.getAttribute('id') === 'catalog_search_results') {
          cl(mutation)
        }
      });
    });

    observer.observe(
      document.querySelector(".catalog_w"),
      {
        childList: true,
        attributes: false,
        subtree: true,
      }
    );
  }

  Array.from(document.querySelectorAll('.card-actions__btn')).map(item => {
    if (item.parentNode.parentNode.querySelector('a')) {
      const href = item.parentNode.parentNode.querySelector('a').href
      let split = '/cars/';
      if (href.includes('/commercial_transports/')) {
        split = '/commercial_transports/';
      }
      if (href.includes('/motorcycles/')) {
        split = '/motorcycles/';
      }
      const slug = href.split(split)[1].split('?')[0];
      const store = new Store('favoritesList');

      const slugsList = store.state.favoritesList.items ? store.state.favoritesList.items.map(item => item.slug) : [];
      const isIncludes = slugsList.includes(slug);

      if (isIncludes) {
        item.classList.toggle('card-actions__delete', true);
        item.classList.toggle('card-actions__add', false);
        item.querySelector('span').innerText = 'Удалить из избранного';
      } else {
        item.classList.toggle('card-actions__delete', false);
        item.classList.toggle('card-actions__add', true);
        item.querySelector('span').innerText = 'Добавить в избранное';
      }
    }
  })
})

$('.pagination__item').click((e) => {
  const page = e.target.innerText;
  history.pushState(null, '', `${window.location.pathname}?page=${page}`);
  catalogSetFavoritesData()
})

$('.pagination__btn').click((e) => {
  const url = new URL(decodeURIComponent(e.target.href)).search
  const page = new URLSearchParams(url).get('page');

  if (page === null) {
    history.pushState(null, '', `${window.location.pathname}`);
  } else {
    history.pushState(null, '', `${window.location.pathname}?page=${page}`);
  }

})

