/**
 * @typedef ItemData
 * @property {string} item_data.item_id - ID машины, товара или любой артикул
 * @property {string} item_data.item_name - Наименование товара
 * @property {string} item_data.item_brand - Бренд
 * @property {string} item_data.price - Цена
 * @property {string} item_data.item_category - Категория
 * @property {string} item_data.item_variant - Вариант, цвет или размер
 * @property {string} item_data.item_list_name - Где показывается товар
 * @property {number} item_data.index - Номер позиции товара в списке
 * @property {number} item_data.quantity - Количество товара
 *
 * @example item_data: {
 *       'item_id': '123432',                     // id товара/артикул
 *       'item_name': 'audi q7 2017',             //название товара
 *       'item_brand': 'audi',                    //бренд, торговая марка
 *       'price': '4650000.00',                   //цена единицы товара
 *       'item_category': 'внедорожник|автомат',  //категория
 *       'item_variant': 'черный',                //вариант/размер/цвет
 *       'item_list_name': 'filtersresults',      //где показывается товар
 *       'index': 1,                              // номер позиции показа товара в списке
 *       'quantity': 1                            // количество товара
 *     }
 */

/**
 * @typedef EventParams - Дополнительные параметры, если запрос был выполнен с примененными фильтрами
 * @property {string} event_params.page_type - Тип страницы
 * @property {object} event_params.active_filters - Примененные фильтры
 *
 * @example event_params: {
 *     page_type: 'filtersresults',  // тип страницы
 *     active_filters: {             // примененные фильтры
 *       кузов: 'седан',
 *       двигатель: 'бензин'
 *     }
 *   }
 */

const EventNames = {
  SELECT_ITEM: 'select_item',
  ADD_TO_CART: 'add_to_cart',
  REMOVE_FORM_CART: 'remove_from_cart',
  BANNER_CLICK: 'banner_click',
  EVENT: 'event',
  ADD_TO_WISHLIST: 'add_to_wishlist',
  ADD_PAYMENT_INFO: 'add_payment_info',
  ADD_SHIPPING_INFO: 'add_shipping_info',
  VIEW_CART: 'view_cart',
  ADD_SHIPPING_INFO: 'add_shipping_info',
  VIEW_ITEM: 'view_item',
  PURCHASE: 'purchase',
}

const usedStateMap = {
  all: 'Все',
  new: 'Новые',
  used: 'С пробегом',
}

const typeVehicleMap = {
  car: 'Легковые',
  commercial_transport: 'Комтранс',
  motorcycle: 'Мото',
}

/**
 * Класс для хранения и управления данными Google Tag Manager (GTM) для автомобилей.
 * Используется для обработки и хранения информации о транспортном средстве.
 */
class VehicleDataStore {
  /**
   * Инициализирует хранилище данных с начальным значением null для gtm_data.
   */
  constructor() {
    /**
     * @type {?Object} GTM данные для текущего транспортного средства.
     */
    this.gtm_data = null
    this.filterData = {
      filters_block: 'big_block',
      category: null,
    }
  }

  /**
   * Устанавливает GTM данные для транспортного средства.
   * @param {Object} data Объект данных GTM для транспортного средства.
   * @example
   * vehicleDataStore.setGtmData({
   *   item_id: 353,
   *   item_name: "Ford Cargo 18xx 2014",
   *   item_brand: "Ford",
   *   price: "688947.36",
   *   item_category: "Бортовой грузовик|Механика",
   *   item_variant: "Коричневый",
   *   item_list_name: "/vehicles/search_only_vehicles",
   *   index: 1,
   *   quantity: 1
   * });
   */
  setGtmData(data) {
    this.gtm_data = data
  }

  /**
   * Получает текущие GTM данные для транспортного средства.
   * @returns {?Object} Текущие GTM данные транспортного средства.
   */
  getGtmData() {
    return this.gtm_data
  }

  /**
   * Очищает GTM данные транспортного средства, устанавливая их в null.
   */
  clearGtmData() {
    this.gtm_data = null
  }

  /**
   * Устанавливает значение для определенного ключа в данных фильтра.
   * @param {string} key Ключ, по которому будет установлено значение в данных фильтра.
   * @param {*} value Значение, которое нужно установить для указанного ключа.
   * @example
   * vehicleDataStore.setFilterData('price', '500000,1000000');
   */
  setFilterData(key, value) {
    this.filterData[key] = value
  }

  /**
   * Получает данные фильтра.
   * @returns {Object} Объект, содержащий текущие значения фильтров.
   * @example
   * vehicleDataStore.getFilterData();
   */
  getFilterData() {
    return this.filterData
  }
}

// Создание экземпляра класса VehicleDataStore.
const vehicleDataStore = new VehicleDataStore()

/**
 * Выводит в консоль объект, если логирование включено.
 * @param {string} label - Метка для лога.
 * @param {object} obj - Объект для логирования.
 */
function logObject(label, obj) {
  if (getCookie('gtmLogging') === 'true') {
    console.log(`${label}: ${JSON.stringify(obj, null, 2)}`)
  }
}

/**
 * Включает логирование GTM, устанавливая соответствующую куку.
 */
function enableGtmLogging() {
  setCookie('gtmLogging', 'true', 1)
}

/**
 * Отключает логирование GTM, удаляя куку логирования.
 */
function disableGtmLogging() {
  deleteCookie('gtmLogging')
}

function sendBannerDataToGTM(
  event_type,
  params = null,
  optional_data = Object.create(null),
) {
  window.dataLayer = window.dataLayer || []
  const clickLocation = window.location.pathname

  if (optional_data && optional_data.ecommerce) {
    window.dataLayer.push({ ecommerce: null }) // https://developers.google.com/analytics/devguides/collection/ga4/ecommerce?client_type=gtm&hl=ru#clearing_the_ecommerce_object
  }

  const eventParams = {
    event: event_type,
    ...optional_data,
  }

  if (params) eventParams.event_params = params
  if (event_type === EventNames.BANNER_CLICK) {
    eventParams.event_params = {
      ...eventParams.event_params,
      location: clickLocation,
    }
  }

  logObject('sendBannerDataToGTM', eventParams)
  window.dataLayer.push(eventParams) // Отправляем данные события
}


/**
 * Обрабатывает изменения типа оплаты, типа доставки или удаление из корзины и отправляет данные в GTM.
 *
 * @param {Event} event - Событие, которое вызвало изменение.
 * @param {string} eventType - Тип события (например, 'payment_type', 'shipping_tier' или 'remove_from_cart').
 * @param {ItemData} gtm_data - Данные товара для передачи в GTM.
 *
 * @example
 *  Для изменения типа оплаты или доставки:
 * handlePaymentDataChange(event, 'payment_type', {
 *   item_id: '123432',
 *   item_name: 'audi q7 2017',
 *   ...
 * });
 *
 *  Для удаления из корзины:
 * handlePaymentDataChange(event, 'remove_from_cart', {
 *   item_id: '132641',
 *   item_name: 'lexus IS 2013',
 *   ...
 * });
 */

function handlePaymentDataChange(
  event,
  eventType,
  gtm_data,
  eventName = EventNames.ADD_PAYMENT_INFO
) {
  if (
    eventType === EventNames.REMOVE_FORM_CART ||
    eventType === EventNames.VIEW_CART
  ) {
    sendBannerDataToGTM(eventType, null, {
      ecommerce: { items: [formatItemData(eventType, gtm_data)] },
    })
    return
  }

  const paymentTypeMapping = {
    online: 'Онлайн',
    upon_delivery: 'При получении',
    distribution_point: 'Пункт выдачи',
    home_delivery: 'Доставка домой',
  }

  const selectedTypeKey = event.target.value
  const selectedTypeValue =
    paymentTypeMapping[selectedTypeKey] || selectedTypeKey

  const eventData = {
    ecommerce: {
      [eventType]: selectedTypeValue,
      items: [formatItemData(eventName, gtm_data)],
    },
  }

  sendBannerDataToGTM(eventName, null, eventData)
}

/**
 * Добавляет событие нажатия на товар в Google Tag Manager
 *
 * @param {ItemData} item_data - Данные для добавления
 * @param {EventParams} [event_params] - Дополнительные параметры, если запрос был выполнен с примененными фильтрами
 * @param {HTMLEvent} - Нативное событие
 * @param {HTMLElement} - Элемент на котором установлен текущий обработчик
 * @param {string} [event_name="select_item"] - Название события
 */
function addCatalogItemDataToGTM(
  item_data,
  event_params,
  event_name = 'select_item',
  event,
  element
) {
  let hasConflicts = false
  if (event && element) hasConflicts = checkConflicts(event, element)
  if (hasConflicts) return
  const isSelectItem = event_name === EventNames.SELECT_ITEM

  window.dataLayer = window.dataLayer || []
  window.dataLayer.push({ ecommerce: null }) // https://developers.google.com/analytics/devguides/collection/ga4/ecommerce?client_type=gtm&hl=ru#clearing_the_ecommerce_object

  if (!item_data.quantity) item_data.quantity = 1

  const payload = {
    event: event_name,
    ...(event_params || {}),
    ecommerce: {
      items: [isSelectItem ? item_data : formatItemData(event_name, item_data)],
    },
  }

  if (event_name === 'select_item') debounceLogAndPush(payload)
  else {
    logObject('addCatalogItemDataToGTM', payload)
    window.dataLayer.push(payload)
  }
}

let debounceTimer;
function debounceLogAndPush(payload, delay = 300) {
  clearTimeout(debounceTimer);
  debounceTimer = setTimeout(() => {
    logObject('addCatalogItemDataToGTM', payload);
    window.dataLayer.push(payload);
  }, delay);
};


