/**
 * Преобразует массив объектов фильтра в один объект.
 *
 * @param {Array<{name: string, value: string}>} filters - Массив объектов фильтров для преобразования.
 * @returns {Object.<string, string> | undefined } Преобразованный объект.
 */
function transformFiltersToObject(filters) {
  if (filters && typeof filters === 'object') {
    // Удаление свойства 'filters_block', если оно существует
    if ('filters_block' in filters) {
      delete filters.filters_block
    }
  }
  return {
    event_params: {
      page_type: 'filtersresults',
      active_filters: filters,
    },
  }
}

/**
 * Возвращает массив видимых элементов на экране по заданному селектору.
 *
 * @param {string} selector - CSS-селектор для выбора элементов.
 * @returns {NodeListOf<Element>} Массив видимых элементов.
 */
function getVisibleElements(selector) {
  const elements = document.querySelectorAll(selector)
  const visibleElements = []

  for (const element of elements) {
    const rect = element.getBoundingClientRect()

    if (
      rect.top >= 0 &&
      rect.left >= 0 &&
      rect.bottom <= window.innerHeight &&
      rect.right <= window.innerWidth
    ) {
      visibleElements.push(element)
    }
  }
  return visibleElements
}

/**
 * Проверяет, есть ли конфликты событий с целью
 *
 * @param {HTMLEvent} event - нативное событие
 * @param {HTMLElement} element - Родительский элемент, на котором было вызвано событие
 * @returns {boolean} Встречается или нет конфликт событий
 */
function checkConflicts(event, element) {
  const { target } = event
  const conflictItemsList = [
    /**
     * Сюда можно добавить селекторы элементов
     * которые вложены в другие элементы,
     * но для них есть свой обработчик событий,
     * который не должен вызывать родительский
     */
    'button.card-actions__add',
  ]

  const conflicts = conflictItemsList.filter((selector) => {
    const conflictItem = element.querySelector(selector)
    return conflictItem === target
  })

  return !!conflicts.length
}

/**
 * Отправляет данные фильтра в Google Tag Manager.
 *
 * @function sendFiltersToGtm
 * @param {string} event_type - Тип события.
 * @param {Object} [event_params=null] - Дополнительные параметры события.
 */
function sendFiltersToGtm(event_type, event_params = null) {
  window.dataLayer = window.dataLayer || []
  const pathname = window.location.pathname
  const location = pathname === '/' ? 'main_page' : 'catalog_page'

  const eventParams = {
    event: event_type,
    event_params: {
      location,
      ...event_params,
    },
  }

  logObject('sendFiltersToGtm', eventParams)
  window.dataLayer.push(eventParams)
}

/**
 * Обрабатывает изменения в радиокнопках и обрабатывает связанные фильтры.
 *
 * @function handleRadioButtonChange
 * @param {string} filters_block - Название или идентификатор блока фильтров.
 * @param {string} usedState - Текущее состояние фильтра "used".
 * @param {string} typeVehicle - Текущий тип транспортного средства.
 * @param {Object} [optionalData={}] - Дополнительные данные для добавления к данным фильтра.
 */
function handleRadioButtonChange(
  filters_block,
  usedState,
  typeVehicle,
  optionalData = Object.create(null),
  isSend = false
) {
  const translatedUsedState = usedStateMap[usedState] || usedState
  const translatedTypeVehicle = typeVehicleMap[typeVehicle] || typeVehicle

  const eventType = isSend ? 'use_filters_send' : 'use_filters'

  sendFiltersToGtm(eventType, {
    category_1: translatedUsedState,
    category_2: translatedTypeVehicle,
    filters_block,
    ...optionalData,
  })
}

/**
 * Просто добавляет событие с определенным именем без дополнительных данных
 *
 * @param {string} event - название события
 */
function simpleEvent(event) {
  if (!event) return

  window.dataLayer = window.dataLayer || []
  window.dataLayer.push({ event_params: null })
  window.dataLayer.push({ event })

  logObject('simpleEvent', { event })
}

