// eslint-disable-next-line no-unused-vars
class HandlerUrlParamsForCatalogFilters {
  constructor(form, params) {
    this.form = form
    this.params = params

    this.setup()
  }

  handle() {
    if (this.params.year && this.yearFilter) this.setYears(this.params.year)
    if (this.params.price && this.priceFilter) this.setPrices(this.params.price)
    if (this.params.horsepower && this.horsepowerFilter) this.setHorsepower(this.params.horsepower)
    if (this.params.body_type) this.setBodyType(this.params.body_type)
    if (this.params.engine_type && this.engineTypeFilter) this.setEngineType(this.params.engine_type)
    if (this.params.transmission && this.transmissionFilter) this.setTransmission(this.params.transmission)
    if (this.params.drive_type && this.driveTypeFilter) this.setDriveType(this.params.drive_type)
    if (this.params.engine_capacity && this.engineCapacityGteOptions) this.setEngineCapacity(this.params.engine_capacity)
    if (this.params.seats_count && this.seatsCountFilter) this.setSeatsCount(this.params.seats_count)
    if (this.params.cargo_volume && this.cargoVolumeFilter) this.setCargoVolume(this.params.cargo_volume)
    if (this.params.actual_lifting_capacity && this.actualLiftingCapacityFilter) {
      this.setActualLiftingCapacity(this.params.actual_lifting_capacity)
    }
  }

  setActualLiftingCapacity(capacities) {
    const actualLiftingCapacityOptions = {
      gte: this.actualLiftingCapacityFilter.gteOptions.filter(option => option.value === capacities.gte)[0],
      lte: this.actualLiftingCapacityFilter.lteOptions.filter(option => option.value === capacities.lte)[0],
    }

    if (capacities.gte && actualLiftingCapacityOptions.gte) {
      this.actualLiftingCapacityFilter.gte.innerText = actualLiftingCapacityOptions.gte.text
    }
    if (capacities.lte && actualLiftingCapacityOptions.lte) {
      this.actualLiftingCapacityFilter.lte.innerText = actualLiftingCapacityOptions.lte.text
    }
  }

  setBodyType(type) {
    const bodyTypeOption = this.bodyTypeOptions.filter(option => option.value == type)[0]
    if (bodyTypeOption) this.bodyType.innerText = bodyTypeOption.text
  }

  setCargoVolume(volume) {
    const cargoVolumeOptions = {
      gte: this.cargoVolumeFilter.gteOptions.filter(option => option.value === volume.gte)[0],
      lte: this.cargoVolumeFilter.lteOptions.filter(option => option.value === volume.lte)[0],
    }

    if (volume.gte && cargoVolumeOptions.gte) {
      this.cargoVolumeFilter.gte.innerText = cargoVolumeOptions.gte.text
    }
    if (volume.lte && cargoVolumeOptions.lte) {
      this.cargoVolumeFilter.lte.innerText = cargoVolumeOptions.lte.text
    }
  }

  setDriveType(type) {
    const driveTypeOption = this.driveTypeOptions.filter(option => option.value === type)[0]
    if (driveTypeOption) this.driveTypeFilter.innerText = driveTypeOption.text
  }

  setEngineCapacity(capacities) {
    const engineCapacityOptions = {
      gte: this.engineCapacityGteOptions.filter(option => option.value === capacities.gte)[0],
      lte: this.engineCapacityLteOptions.filter(option => option.value === capacities.lte)[0],
    }

    if (capacities.gte && engineCapacityOptions.gte) this.engineCapacityGte.innerText = engineCapacityOptions.gte.text
    if (capacities.lte && engineCapacityOptions.lte) this.engineCapacityLte.innerText = engineCapacityOptions.lte.text
  }

  setEngineType(type) {
    const engineTypeOption = this.engineTypeOptions.filter(option => option.value == type)[0]
    if (engineTypeOption) this.engineTypeFilter.innerText = engineTypeOption.text
  }

  // данную функцию надо вызывать отдельно, так как список поколений формируется отдельным запросом
  setGenerations(type) {
    const generationOptions = Array.from(this.form.car_generation_id.options)
    const generationTypeOption = generationOptions.filter(option => option.value === type)[0]

    if (generationTypeOption) this.generationFilter.innerText = generationTypeOption.text
  }

  setHorsepower(powers) {
    const horsepowerOptions = {
      gte: this.horsepowerFilter.gteOptions.filter(option => option.value === powers.gte)[0],
      lte: this.horsepowerFilter.lteOptions.filter(option => option.value === powers.lte)[0],
    }

    if (powers.gte && horsepowerOptions.gte) this.horsepowerFilter.gte.innerText = horsepowerOptions.gte.text
    if (powers.lte && horsepowerOptions.lte) this.horsepowerFilter.lte.innerText = horsepowerOptions.lte.text
  }

  setPrices(prices) {
    let formattedPrice = '';

    const priceOptions = {
      gte: this.priceFilter.gteOptions.filter(option => option.value === prices.gte)[0],
      lte: this.priceFilter.lteOptions.filter(option => option.value === prices.lte)[0],
      gte_mobile: this.priceFilter.gteOptions.filter(option => option.value === prices.gte_mobile)[0],
      lte_mobile: this.priceFilter.lteOptions.filter(option => option.value === prices.lte_mobile)[0],
    }

    const isGteExist = prices.gte && priceOptions.gte
    const isLteExist = prices.lte && priceOptions.lte

    function extractNumbers(str) {
        return str.replace(/\D/g, '');
    }

    if (isGteExist) {
      this.priceFilter.gte.innerText = extractNumbers(priceOptions.gte.text)
      this.priceFilter.gte_mobile.innerText = extractNumbers(priceOptions.gte.text)
      formattedPrice = `${extractNumbers(priceOptions.gte.text)},`;
    }
    if (prices.lte && priceOptions.lte) {
      this.priceFilter.lte.innerText = extractNumbers(priceOptions.lte.text)
      this.priceFilter.lte_mobile.innerText = extractNumbers(priceOptions.lte.text)
      formattedPrice = `,${extractNumbers(priceOptions.lte.text)}`;
    }
    if (isGteExist && isLteExist) {
      formattedPrice = `${extractNumbers(priceOptions.gte.text)},${extractNumbers(priceOptions.lte.text)}`;
    }

    vehicleDataStore.setFilterData('Цена', formattedPrice)
  }

  setSeatsCount(count) {
    const seatsCountOptions = {
      gte: this.seatsCountFilter.gteOptions.filter(option => option.value === count.gte)[0],
      lte: this.seatsCountFilter.lteOptions.filter(option => option.value === count.lte)[0],
    }

    if (count.gte && seatsCountOptions.gte) this.seatsCountFilter.gte.innerText = seatsCountOptions.gte.text
    if (count.lte && seatsCountOptions.lte) this.seatsCountFilter.lte.innerText = seatsCountOptions.lte.text
  }

  setTransmission(type) {
    const transmissionOption = this.transmissionOptions.filter(option => option.value === type)[0]
    if (transmissionOption) this.transmissionFilter.innerText = transmissionOption.text
  }

  setYears(years) {
    const yearOptions = {
      gte: this.yearFilter.gteOptions.filter(option => option.value == years.gte)[0],
      lte: this.yearFilter.lteOptions.filter(option => option.value == years.lte)[0],
    }

    if (years.gte && yearOptions.gte) this.yearFilter.gte.innerText = yearOptions.gte.text
    if (years.lte && yearOptions.lte) this.yearFilter.lte.innerText = yearOptions.lte.text
  }

  setup() {
    // Год выпуска
    const year = {
      gte: document.getElementById('year_mkp_gte'),
      lte: document.getElementById('year_mkp_lte'),
    }
    if (year.gte && year.lte) {
      this.yearFilter = {
        gte: year.gte.getElementsByClassName('select__input')[0],
        gteOptions: Array.from(this.form.year_gte.options),
        lte: year.lte.getElementsByClassName('select__input')[0],
        lteOptions: Array.from(this.form.year_lte.options),
      }
    }

    // Цена
    const price = {
      // В данной версии кода получали всегда элемент десктопного фильтра (используются одинаковые id у фильтров
      // для десктопа и мобильной версии)
      //
      // gte: document.getElementById('price_mkp_gte'),
      // lte: document.getElementById('price_mkp_lte'),
      gte: document.querySelectorAll('#price_mkp_gte')[0],
      lte: document.querySelectorAll('#price_mkp_lte')[0],
      gte_mobile: document.querySelectorAll('#price_mkp_gte')[1],
      lte_mobile: document.querySelectorAll('#price_mkp_lte')[1],
    }

    if (price.gte && price.lte && price.gte_mobile && price.lte_mobile) {
      this.priceFilter = {
        gte: price.gte.getElementsByClassName('select__input')[0],
        gte_mobile: price.gte_mobile.getElementsByClassName('select__input')[0],
        gteOptions: Array.from(this.form.price_gte.options),
        lte: price.lte.getElementsByClassName('select__input')[0],
        lte_mobile: price.lte_mobile.getElementsByClassName('select__input')[0],
        lteOptions: Array.from(this.form.price_lte.options),
      }
    }

    // Мощность
    const horsepower = {
      gte: document.getElementById('horsepower_mkp_gte'),
      lte: document.getElementById('horsepower_mkp_lte'),
    }

    if (horsepower.gte && horsepower.lte) {
      this.horsepowerFilter = {
        gte: horsepower.gte.getElementsByClassName('select__input')[0],
        gteOptions: Array.from(this.form.horsepower_gte.options),
        lte: horsepower.lte.getElementsByClassName('select__input')[0],
        lteOptions: Array.from(this.form.horsepower_lte.options),
      }
    }

    // Кузов
    const bodyType = document.getElementById('body_type_mkp')
    if (bodyType) {
      this.bodyType = bodyType.getElementsByClassName('select__input')[0]
      this.bodyTypeOptions = Array.from(this.form.body_type.options)
    }

    // Двигатель
    const engineType = document.getElementById('engine_type_mkp')
    if (engineType) {
      this.engineTypeFilter = engineType.getElementsByClassName('select__input')[0]
      this.engineTypeOptions = Array.from(this.form.engine_type.options)
    }

    // Коробка
    const transmission = document.getElementById('transmission_mkp')
    if (transmission) {
      this.transmissionFilter = transmission.getElementsByClassName('select__input')[0]
      this.transmissionOptions = Array.from(this.form.transmission.options)
    }

    // Привод
    const driveType = document.getElementById('drive_type_mkp')
    if (driveType) {
      this.driveTypeFilter = driveType.getElementsByClassName('select__input')[0]
      this.driveTypeOptions = Array.from(this.form.drive_type.options)
    }

    // Поколение
    const generationWrap = document.getElementById('generations')
    if (generationWrap) {
      this.generationFilter = generationWrap.getElementsByClassName('select__input')[0]
    }

    // Объем двигателя
    const engineCapacityGte = document.getElementById('engine_capacity_mkp_gte')
    const engineCapacityLte = document.getElementById('engine_capacity_mkp_lte')
    if (engineCapacityGte && engineCapacityLte) {
      this.engineCapacityGte = engineCapacityGte.getElementsByClassName('select__input')[0]
      this.engineCapacityGteOptions = Array.from(this.form.engine_capacity_gte.options)

      this.engineCapacityLte = engineCapacityLte.getElementsByClassName('select__input')[0]
      this.engineCapacityLteOptions = Array.from(this.form.engine_capacity_lte.options)
    }

    // Грузоподъёмность
    const actualLiftingCapacity = {
      gte: document.getElementById('actual_lifting_capacity_mkp_gte'),
      lte: document.getElementById('actual_lifting_capacity_mkp_lte'),
    }
    if (actualLiftingCapacity.gte && actualLiftingCapacity.lte) {
      this.actualLiftingCapacityFilter = {
        gte: actualLiftingCapacity.gte.getElementsByClassName('select__input')[0],
        gteOptions: Array.from(this.form.actual_lifting_capacity_gte.options),
        lte: actualLiftingCapacity.lte.getElementsByClassName('select__input')[0],
        lteOptions: Array.from(this.form.actual_lifting_capacity_lte.options),
      }
    }

    // Объем грузового отсека
    const cargoVolume = {
      gte: document.getElementById('cargo_volume_mkp_gte'),
      lte: document.getElementById('cargo_volume_mkp_lte'),
    }
    if (cargoVolume.gte && cargoVolume.lte) {
      this.cargoVolumeFilter = {
        gte: cargoVolume.gte.getElementsByClassName('select__input')[0],
        gteOptions: Array.from(this.form.cargo_volume_gte.options),
        lte: cargoVolume.lte.getElementsByClassName('select__input')[0],
        lteOptions: Array.from(this.form.cargo_volume_lte.options),
      }
    }

    // Количество мест
    const seatsCount = {
      gte: document.getElementById('seats_count_mkp_gte'),
      lte: document.getElementById('seats_count_mkp_lte'),
    }
    if (seatsCount.gte && seatsCount.lte) {
      this.seatsCountFilter = {
        gte: seatsCount.gte.getElementsByClassName('select__input')[0],
        gteOptions: Array.from(this.form.seats_count_gte.options),
        lte: seatsCount.lte.getElementsByClassName('select__input')[0],
        lteOptions: Array.from(this.form.seats_count_lte.options),
      }
    }
  }
};
