var initStickyCatalog = function() {
  var catalogFilter = document.querySelector('.js-catalog-filter')
  var catalogFilterWrapper = document.querySelector('.cars__sidebar')
  var footer = document.querySelector('.footer')

  if (!catalogFilter) return

  function step() {
    if (window.scrollY >= 67) {
      catalogFilter.classList.add('is_stuck')
      catalogFilter.style.position = 'fixed'
      catalogFilter.style.width = catalogFilterWrapper.offsetWidth + 'px'
    }
    else {
      catalogFilter.classList.remove('is_stuck')
      catalogFilter.style.removeProperty('width')
      catalogFilter.style.removeProperty('position')
    }

    if (window.scrollY >= document.body.scrollHeight - footer.offsetHeight - window.innerHeight) {
      catalogFilter.style.width = catalogFilterWrapper.offsetWidth + 'px'
      catalogFilter.style.bottom = '0'
      catalogFilter.style.position = 'absolute'
      catalogFilter.style.top = 'auto'
    }
    else {
      catalogFilter.style.removeProperty('bottom')
      catalogFilter.style.removeProperty('top')
    }

    window.requestAnimationFrame(step);
  }

  window.requestAnimationFrame(step);
};
var initVehicleListPlugins = function() {
  var initTooltip = function(el) {
    if($('html').hasClass('mobile')){
      $('[data-toggle="tooltip"]').tooltip({
        container: 'body',
        trigger: 'click',
        animation: false,
        html: function() {
          return $(this).attr("title");
        }
      });
    } else {
      $('[data-toggle="tooltip"]').tooltip({
        container: 'body',
        trigger: 'hover',
        html: function() {
          return $(this).attr("title");
        }
      });
    }

    $('[data-toggle="tooltip"]').on('click touchstart', function (event) {
      if ($(this).hasClass("main-title__info")) {
        event.stopPropagation();
      }
    });
  }

  var initVehicleCard = function(el) {
    initTooltip()

    el.owlCarousel({
      lazyLoad: true,
      items: 1,
      nav: true,
      dots: false,
      lazyload: true,
      navText: GLOBAL_CONSTANTS.nav_icons,
      loop: true,
      mouseDrag: true,
      dotsEach: 1,
      responsive:{
        0:{
          touchDrag: true
        },
        680:{
          touchDrag: false
        },
      },
    });
  }

  function isElementInViewport (el) {
    // Special bonus for those using jQuery
    if (typeof jQuery === "function" && el instanceof jQuery) {
      el = el[0];
    }

    var rect = el.getBoundingClientRect();

    return (
      rect.top >= 0 &&
      rect.left >= 0 &&
      rect.bottom <= 400 + (window.innerHeight || document.documentElement.clientHeight) && /* or $(window).height() */
      rect.right <= (window.innerWidth || document.documentElement.clientWidth) /* or $(window).width() */
    );
  }

  var $searchResult = $('#catalog_search_results')
  var responseHtml = $searchResult.data('html')
  $searchResult.html(responseHtml)

  var $carousels = $searchResult.find('.js-vehicle-list-carousel')

  $carousels.slice(0, 6).each(function(_, el) {
    initVehicleCard($(el))
  })

  $('.pagination__item').click((e) => {
    const page = e.target.innerText;
    history.pushState(null, '', `${window.location.pathname}?page=${page}`);
  })

  $('.pagination__btn').click((e) => {
    const url = new URL(decodeURIComponent(e.target.href)).search
    const page = new URLSearchParams(url).get('page');

    if (page === null) {
      history.pushState(null, '', `${window.location.pathname}`);
    } else {
      history.pushState(null, '', `${window.location.pathname}?page=${page}`);
    }

  })

  setTimeout(function() {
    $(window).on('scroll resize', function() {

      $carousels.not('.owl-loaded').each(function(_, el) {
        if (isElementInViewport($(el).parents('.card'))) {
          initVehicleCard($(el))
        }
      })
    })
  }, 1000)
};
class InputValidator {
  /**
   * @param {string} selector - селектор поля, который нуждается в дополнительной валидации
   * @param {RegExp} pattern - регулярное выражение по которому происходит валидация
   * @param {boolean} required - если поле обязательно, оно будет дополнительно проверено на пустое значение
   * @param {string} errorMessage - сообщение, которое будет выводиться при ошибке валидации
   */
  constructor(selector, pattern, required = false, errorMessage) {
    this.selector = selector;
    this.pattern = pattern;
    this.required = required;
    this.errorMessage = errorMessage;
    this.processInput = this.debounceInput(this.validateInput.bind(this));
    this.initialize();
  }

  /**
   * @param {string} message - сообщение которое будет выводиться в подсказке при ошибке валидации
   * @returns {HTMLElement} - сам HTML элемент который будет создан на основе текста ошибки
   */
  createErrorElement(message = '') {
    const errorElement = document.createElement('span');
    errorElement.classList.add('error_msg');
    errorElement.innerText = message;
    return errorElement;
  }

  /**
   * @param {function} func
   * @param {number} timeout
   * @returns {function}
   */
  debounceInput(func, timeout = 800) {
    let timer;
    return (...args) => {
      clearTimeout(timer);
      timer = setTimeout(() => { func.apply(this, args); }, timeout);
    };
  }

  /**
   * @param {HTMLInputElement} target - целевой элемент который будет провалидирован
   */
  validateInput(target) {
    const { value } = target;
    const isInputValid = this.pattern.test(value);
    const isValueEmpty = value === '' && this.required;
    const parent = target.closest('label');

    if (parent && parent.classList.contains('error')) {
      parent.classList.remove('error');
    }

    this.removeExistingErrors(target);

    if (isValueEmpty) {
      target.after(this.createErrorElement('Поле обязательно для заполнения'));
      if (parent) parent.classList.add('error');
    } else if (!isInputValid) {
      target.after(this.createErrorElement(this.errorMessage));
      if (parent) parent.classList.add('error');
    } else if (parent) parent.classList.remove('error');
  }

  removeExistingErrors(target) {
    const errorElements = target.parentNode.querySelectorAll('.error_msg');
    errorElements.forEach(error => error.remove());
  }

  initialize() {
    const fields = document.querySelectorAll(this.selector);

    fields.forEach((field) => {
      field.oninput = ({ target }) => {
        this.processInput(target);
      };
    });
  }
}

window.onload = () => {
  new InputValidator('input:not([class*="__input"]).string.email', /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/, true, 'Вы указали неверный email');
  new InputValidator('input:not([class*="__input"]).string.tel', /\+7 \d{3}\s\d{3}\s\d{4}/, true, 'Вы указали неверный номер');
  new InputValidator('input:not([class*="__input"]).required:not(.email):not(.tel)', /.+/, true, 'Поле обязательно для заполнения');
};
