(function() {
  this.initDealerMap = function(lat, lng) {
    var FreshDealer, image, map, mapCanvas, mapOptions, marker, size, url;
    mapCanvas = document.getElementById('map-container');
    FreshDealer = {
      lat: lat,
      lng: lng
    };
    mapOptions = {
      center: FreshDealer,
      zoom: 16,
      scrollwheel: false
    };
    map = new google.maps.Map(mapCanvas, mapOptions);
    url = "/assets/general/pin-94df4438d90005260d4e62ea711a8de0d03a62b231968f1534a66ca304e6c65c.png";
    size = new google.maps.Size(37, 34);
    if (window.devicePixelRatio > 1.5) {
      size = new google.maps.Size(74, 68);
    }
    image = {
      url: url,
      scaledSize: new google.maps.Size(37, 34),
      origin: new google.maps.Point(0, 0),
      anchor: new google.maps.Point(16, 37)
    };
    marker = new google.maps.Marker({
      position: FreshDealer,
      map: map,
      icon: image
    });
  };

}).call(this);
