(function() {
  $(function() {
    $('.header__right .callback, .footer .callback').fancybox({
      padding: 0,
      margin: 0,
      fitToView: false,
      width: '100%',
      height: 'auto',
      autoSize: false,
      closeClick: false,
      openEffect: 'none',
      closeEffect: 'none',
      helpers: {
        overlay: {
          css: {
            'background': 'rgba(0, 0, 0, .5)'
          }
        }
      },
      wrapCSS: 'pp-callback-w'
    });
    return $('.main-search .btn-buy').fancybox({
      padding: 0,
      margin: 0,
      fitToView: false,
      width: '100%',
      height: '100%',
      autoSize: false,
      closeClick: false,
      openEffect: 'none',
      closeEffect: 'none',
      helpers: {
        overlay: {
          css: {
            'background': 'rgba(0, 0, 0, .5)'
          }
        }
      },
      wrapCSS: 'pp-main'
    });
  });

  $(document).on('click', '.popup-w .catalog-controls ul li a', function(e) {
    var $this, carBrandsItems, index;
    e.preventDefault();
    $this = $(this);
    index = $this.closest('li').index();
    $('.catalog-controls ul li').removeClass('active');
    $this.closest('li').addClass('active');
    carBrandsItems = $('.car-brands-tabs .car-brands-tabs__item');
    carBrandsItems.removeClass('active').eq(index).addClass('active');
    if (!carBrandsItems.eq(index).hasClass('initcol')) {
      carBrandsItems.eq(index).addClass('initcol');
    }
  });

  $(document).on('click', '.pp-city .close-pp-city', function(e) {
    e.preventDefault();
    $(this).parents('.pp-city').hide();
    $('body').removeClass('pp-open');
  });

}).call(this);
(function() {
  this.showPreloader = function() {
    var div, overlay, ring;
    overlay = $("<div></div>");
    overlay.addClass("preloader-overlay");
    div = $("<div></div>");
    ring = $('<div class="uil-ring-css"><div>');
    div.append(ring);
    overlay.append(div);
    return $('body').append(overlay);
  };

  this.hidePreloader = function() {
    return $('.preloader-overlay').remove();
  };

}).call(this);
