(function() {
  var search, tryToSearch;

  $(document).on('focus', '.main-search-i .search-row__input .search-field, .car-form .search-field', function(e) {
    return $(this).parent().find(".search-dropdown").addClass("open");
  });

  $(document).on('keyup', '#main-search, .car-form .search-field', function(e) {
    var searchQuery, searchURL;
    searchQuery = $(this).val();
    searchURL = $(this).data('url');
    return tryToSearch(searchQuery, searchURL, e);
  });

  $(document).on('keyup', '.search-field', function(e) {
    var searchQuery;
    searchQuery = $(this).val();
    if (!searchQuery.length) {
      return $('.search_results').html("");
    }
  });

  $(document).on('click', 'body', function(e) {
    if (!$(this).hasClass('search-field')) {
      return $('.search_results').html("");
    }
  });

  $(document).on('click', '.js-search-form__selected_prod .selected_prod_block .js-remove-selected', function(e) {
    document.dispatchEvent(new CustomEvent('CarSearchRemove'));
    $('.js-search-form__selected_prod').html('').hide();
    $('.js-search-form__line').addClass('open result').show();
    $('#request_vehicle_id').val("");
    $('#request_vehicle_type').val("");
    return e.preventDefault();
  });

  $(document).on('click', '.search_results .result-link', function(e) {
    var select_vehicle_event, vehiclePreview;
    e.preventDefault();
    $(this).parents('.search-dropdown').removeClass("open");
    $('.js-search-form__line').removeClass('open preload result').hide();
    vehiclePreview = $(this).find('>a').html();
    $('.js-search-form__selected_prod').show().html("<div class='selected_prod_block'>" + vehiclePreview + "</div>");
    $('.js-search-form__selected_prod .selected_prod_block').append($('<button>').attr('title', 'Удалить').attr('aria-label', 'Удалить').addClass('remove_selected js-remove-selected').html($('.js-close-icon').html()));
    $('#request_vehicle_id').val($(this).data('vehicle-id'));
    $('#request_vehicle_type').val($(this).data('vehicle-type'));
    select_vehicle_event = new CustomEvent('CarSearchFormFieldUpdated', {
      bubbles: true,
      detail: {
        vehicle_id: $(this).data('vehicle-id'),
        vehicle_type: $(this).data('vehicle-type'),
        vehicle_price: $(this).data('vehicle-price')
      }
    });
    return this.dispatchEvent(select_vehicle_event);
  });

  tryToSearch = function(searchQuery, searchURL, e) {
    if (e.keyCode !== 13 && searchQuery.length > 1) {
      clearTimeout($.data(this, 'timer'));
      return $(this).data('timer', setTimeout((function() {
        search(searchQuery, searchURL);
      }), 500));
    }
  };

  search = function(searchQuery, searchURL) {
    $('.js-search-form__line').addClass('open preload');
    return $.get(searchURL + '?q=' + searchQuery);
  };

}).call(this);
