class DealersFilters {
  constructor(filters, dealers) {
    this.$el = $(filters)
    this.$select = this.$el.find('.js-dealers-select')
    this.$select2 = this.$select.find('select')
    this.dealers = dealers
    this.events = {}
    this.filterState = {
      types: [],
      cityId: -1,
    }
    this.initSelect2(this.dealers)
    this.initCheckboxes('.js-dealers-filters-types')
  }

  filterByRadio(state, collection) {
    if (state.types.length === 0) {
      return collection
    }

    return collection.filter(dealer => {
      const match = dealer.type.some(type => state.types.indexOf(type) >= 0)

      if (match) {
        return dealer
      }
    })
  }

  filterByCity(state, dealers) {
    if (state.cityId === -1) {
      return dealers
    }

    return dealers.filter(dealer => dealer.city.id === state.cityId)
  }

  filteredDealers(filterOnlyCities = false) {
    const state = this.filterState
    const cities = this.filterByCity(state, this.dealers)

    if (filterOnlyCities) {
      return cities
    }

    return this.filterByRadio(state, cities)
  }

  prepareSelectOptions(dealers) {
    const selectOptions = [{ id: -1, text: 'Все города' }]

    dealers.forEach(dealer => {
      const alreadyExists = selectOptions.some(item => item.id === dealer.city.id)

      if (!alreadyExists) {
        selectOptions.push({ id: dealer.city.id, text: dealer.city.name })
      }
    })

    return selectOptions
  }

  initCheckboxes(selector) {
    this.$el.find(selector).on('change', 'input', event => {
      let types = this.filterState.types
      const state = event.target.checked
      const value = event.target.value

      if (state) {
        types.push(value)
      }
      else {
        types.splice(types.indexOf(value), 1)
      }

      this.emit('change-radio', this.filteredDealers())
    })
  }

  resetCheckboxes(selector) {
    this.$el.find(selector).each((_, el) => {
      $(el).find('input').prop('checked', false)
    })
  }

  initSelect2(dealers) {
    const formatState = state => {
      if (state.id === '-1') {
        return $(
          '<div class="option-item">' +
          '<div>' +
          state.text +
          '</div>' +
          '</div>'
        )
      }

      return state.text
    }

    this.$select2.select2({
      minimumResultsForSearch: Infinity,
      placeholder: 'Все города',
      data: this.prepareSelectOptions(dealers),
      width: '100%',
      dropdownCssClass: 'dealers-filters-container',
      templateResult: formatState,
    })

    this.$select2.on('change', event => {
      this.filterState.types = []
      this.filterState.cityId = parseInt(event.target.value)
      this.resetCheckboxes('.js-dealers-filters-types')
      this.emit('change-select', this.filteredDealers(true))
    })
  }

  setSelectValue(val) {
    this.filterState.cityId = val
    this.$select2.val(val).trigger('change.select2')
  }

  subscribe(eventName, fn) {
    if (!this.events[eventName]) {
      this.events[eventName] = []
    }

    this.events[eventName].push(fn)
  }

  emit(eventName, data) {
    const event = this.events[eventName]
    if (event) {
      event.forEach(fn => {
        fn.call(null, data)
      })
    }
  }
};
class DealersMap {
  constructor(dealers) {
    this.dealers = dealers
    this.map = null
    this.clusterer = null
    this.myGeoObjects = []

    ymaps.ready(this.createMap.bind(this, this.dealers))
  }

  createMap(dealers) {
    this.map = new ymaps.Map('dealersMap', {
      center: [51.51, 40.51],
      zoom: 5,
      controls: ['fullscreenControl', 'zoomControl'],
    })

    this.clusterer = new ymaps.Clusterer({
      clusterIconColor: '#003DFF',
      zoomMargin: 100,
    })

    this.map.behaviors.disable('scrollZoom')
    this.setPlaceMarkers(dealers)
  }

  getSelectedDealersBounds(dealers) {
    if (dealers.length === 1) {
      const { latitude, longitude } = dealers[0]
      return this.map.setCenter([latitude, longitude], 16)
    }

    this.map.setBounds(this.getBoundsCoords(dealers))

    if (this.map.getZoom() > 16) {
      this.map.setZoom(17)
    }
  }

  getBoundsCoords(dealers) {
    const coords = dealers.reduce((prev, { latitude, longitude }) => {
      if (!latitude && !longitude) {
        return prev
      }

      prev.x.push(latitude)
      prev.y.push(longitude)

      return prev
    }, { x: [], y: [] })

    const minXCoords = Math.min.apply(null, coords.x)
    const minYCoords = Math.min.apply(null, coords.y)
    const maxXCoords = Math.max.apply(null, coords.x)
    const maxYCoords = Math.max.apply(null, coords.y)

    return [[minXCoords, minYCoords], [maxXCoords, maxYCoords]]
  }

  createHintLayout() {
    return ymaps.templateLayoutFactory.createClass(
      "<div class='dealers-map-hint'>" +
      "<div class='container'>" +
      "{{ properties.title }}" +
      "</div></div>"
    )
  }

  createPlaceMarker(latitude, longitude, dealer) {
    const HintLayout = this.createHintLayout()

    return new ymaps.Placemark(
      [latitude, longitude],
      {
        id: dealer.id,
        cityId: dealer.city.id,
        title: dealer.title,
      },
      {
        hintLayout: HintLayout,
        iconLayout: 'default#image',
        iconImageClipRect: [[0,0], [39, 34]],
        iconImageHref: '/marker.svg',
        iconImageSize: [39, 34],
        iconImageOffset: [-13, -34],
      }
    )
  }

  setPlaceMarkers(dealers) {
    const map = this.map
    const clusterer = this.clusterer
    const myGeoObjects = this.myGeoObjects

    dealers.forEach(dealer => {
      const { latitude, longitude } = dealer

      if (!latitude && !longitude) {
        return
      }

      const placemark = this.createPlaceMarker(latitude, longitude, dealer)

      placemark.events.add('click', event => {
        const dealerTarget = event.get('target').properties

        $(document).trigger('dealers-hint-click', {
          id: dealerTarget.get('id'),
          cityId: dealerTarget.get('cityId'),
        })
      })

      myGeoObjects.push(placemark)
      clusterer.add(myGeoObjects)
      map.geoObjects.add(clusterer)
    })

    map.setBounds(map.geoObjects.getBounds())
  }
};



$(document).ready(function() {
  const selector = '.js-dealers-page'

  class DealersPage {
    constructor(selector) {
      this.$el = $(selector)
      this.dealers = this.getDealers()
      this.$el.removeAttr('data-dealers')
      this.map = new DealersMap(this.dealers)
      this.dealersFilters = new DealersFilters('.js-dealers-filters', this.dealers)
      this.bindEvents()
    }

    bindEvents() {
      $(document).on('dealers-hint-click', (event, payload) => {
        this.dealersFilters.setSelectValue(payload.cityId)
        this.rerenderDealerCards(this.findDealer(payload.id))
      })

      this.dealersFilters.subscribe('change-select', this.handleFilterChange.bind(this))
      this.dealersFilters.subscribe('change-radio', this.rerenderDealerCards.bind(this))
    }

    handleFilterChange(dealers) {
      this.map.getSelectedDealersBounds(dealers)
      this.rerenderDealerCards(dealers)
    }

    getDealers() {
      return this.$el.data('dealers').sort((a, b) => a.city.name.localeCompare(b.city.name))
    }

    findDealer(id) {
      return this.dealers.filter(dealer => dealer.id === id)
    }

    rerenderDealerCards(filteredDealers) {
      const $dealerCards = this.$el.find('.dealer-card')

      if (!filteredDealers.length) {
        return $dealerCards.addClass('hidden')
      }

      const isVisible = dealerId => filteredDealers.some(item => {
        return item.id === dealerId
      })


      this.dealers.forEach(dealer => {
        const $dealerCard = $dealerCards.filter('[data-dealer-id=' + dealer.id + ']')

        if (isVisible(dealer.id)) {
          $dealerCard.removeClass('hidden')
        }
        else {
          $dealerCard.addClass('hidden')
        }
      })
    }
  }

  if ($(selector).length) {
    new DealersPage(selector)
  }
});
let favoritesSyncSeq = 0;

const getFavoritesCars = async () => {
    const seq = ++favoritesSyncSeq;

    const store = new Store('favoritesList');
    const token = getCookie('accessToken');

    if (!token) {
        if (seq !== favoritesSyncSeq) return [];
        store.dispatch({ type: 'CLEAR_DATA' });
        showFavNotify(false);
        return [];
    }

    try {
        const res = await createRequest('GET', {
            accept: 'application/json',
            Authorization: `Bearer ${token}`,
        })('/api/v2/users/favourite-slugs');

        if (seq !== favoritesSyncSeq) return [];

        const items = Array.isArray(res?.items) ? res.items.filter(Boolean) : [];
        const total = Number.isFinite(Number(res?.total)) ? Number(res.total) : items.length;

        const favoritesList = { ...res, items, total };

        store.dispatch({
            type: 'SET_DATA',
            payload: { favoritesList },
        });

        showFavNotify(total > 0);
        return items;
    } catch {
        if (seq !== favoritesSyncSeq) return [];
        store.dispatch({ type: 'CLEAR_DATA' });
        showFavNotify(false);
        return [];
    }
};


const showFavNotify = (state) => {
    const store = new Store('favoritesList');

    const totalRaw = store.state?.favoritesList?.total;
    const items = store.state?.favoritesList?.items;

    const favorites_count = Number.isFinite(Number(totalRaw))
        ? Number(totalRaw)
        : (Array.isArray(items) ? items.length : 0);

    const icon = document.querySelector('.profile-menu__icon');
    const favLink = document.querySelector('.profile-menu__item[href="/user/favorites/"]');
    const counter = document.querySelector('.profile-menu__item[href="/user/favorites/"] .count-notify');

    if (icon) icon.classList.toggle('favorites-counter', state);
    if (favLink) favLink.classList.toggle('is-active', state);

    if (counter) counter.innerText = String(favorites_count);
};

const getUserIdFromLocalStorage = () => {
    try {
        const raw = localStorage.getItem('user');
        if (!raw) return null;

        const parsed = JSON.parse(raw);
        const idRaw = parsed?.dto?.id ?? parsed?.id;

        const id = Number(idRaw);
        return Number.isFinite(id) && id > 0 ? id : null;
    } catch {
        return null;
    }
};

const addSlugToFavorites = async (slug = null) => {
    const token = getCookie('accessToken');
    const userId = getUserIdFromLocalStorage();

    if (!slug || !token || !userId) return false;

    try {
        const data = await createRequest('POST', {
            accept: 'application/json',
            'Content-Type': 'application/json',
            Authorization: `Bearer ${token}`,
        })('/api/v2/users/favourite-slugs', {
            user_id: userId,
            slug,
        });

        getFavoritesCars().catch(() => {});

        showFavoritesNotify();
        return data;
    } catch {
        return false;
    }
};

const removeSlugFromFavorites = async (slug = null) => {
    const token = getCookie('accessToken');

    if (!slug || !token) return false;

    try {
        await createRequest('DELETE', {
            accept: 'application/json',
            Authorization: `Bearer ${token}`,
        })(`/api/v2/users/favourite-slugs/${slug}`);

        getFavoritesCars().catch(() => {});
        return true;
    } catch {
        return false;
    }
};

const showFavoritesNotify = () => {
    const modal = document.querySelector('.favoriteModal');

    if (modal) {
        modal.classList.add('active');
        setTimeout(() => {
            modal.classList.remove('active');
        }, 5000);
    }
};
