function compareHeight() {
  $('.page-compare__carousel').each(function () {
    $(this).find('.owl-item').eq(0).find('li').each(function () {
      var curIndex = $(this).index(),
        maxHeight = 0;

      $(this).closest('.owl-stage').find('.owl-item').each(function () {
        $(this).find('li').eq(curIndex).css('height', 'auto');
      });

      $(this).closest('.owl-stage').find('.owl-item').each(function () {
        if($(this).find('li').eq(curIndex).outerHeight() > maxHeight) {
          maxHeight = $(this).find('li').eq(curIndex).outerHeight();
        }
      });
      $(this).closest('.owl-stage').find('.owl-item').each(function () {
        $(this).find('li').eq(curIndex).css('height', maxHeight);
      });
    });
  });
}

