function fixHeader() {
  header = $('.vehicle-header__placeholder');
  headerHeight = header.outerHeight();
  breakpoint = headerHeight + $('header.header').outerHeight();
  target = $('.vehicle-header__container');
  scroll = $(window).scrollTop();
  const quarantine = $('#quarantine-button');
  const quarantineLink = quarantine.find('.quarantine-button__inner');
  const quarantineIsHidden = quarantine.hasClass('quarantine-button_hidden') || localStorage.getItem('quarantine-button-hidden');
  const isMobile = window.innerWidth < 768;

  if (scroll > breakpoint && !target.hasClass('is-fixed')) {
    target.css('visibility', 'hidden');
    target.addClass('is-fixed');
    target.css('visibility', 'visible');

    if (isMobile && !quarantineIsHidden) {
      quarantineLink.css('top', (headerHeight - 3) + 'px');
    }
  } else if (scroll < breakpoint && target.hasClass('is-fixed')) {
    target.css('visibility', 'hidden');
    target.removeClass('is-fixed');
    target.css('visibility', 'visible');

    if (isMobile && !quarantineIsHidden) {
      quarantineLink.css('top', breakpoint - headerHeight + 'px');
    }
  }
}

function initSelect() {
  var select = $('.select');

  var selected = new CustomEvent("selected", {
    detail: {},
    bubbles: true,
    cancelable: true
  });

  select.find('.select__input').filter(':empty').map(function() {
    var select = $(this).closest('.select');
    var first_option = select.find('.select__option').first();

    if (select.hasClass('select_checkbox')) {
      $(this).text(first_option.text().trim());
    } else {
      if(first_option.length === 1) {
        $(this).text(first_option.html().slice(0, first_option.html().indexOf('<span>')).trim());
      }
    }
  })

  select.on('click', '.select__static', function() {
    var thisSelect = $(this).closest('.select');

    if (thisSelect.hasClass('select_disabled')) {
      return;
    }

    if (!thisSelect.hasClass('select_opened')) {
      $('body').on('click', function(e) {
        if (thisSelect.has(e.target).length === 0) {
          thisSelect.removeClass('select_opened');
        }
      })
      $('.filter__line').removeClass('active');
    }

    thisSelect.toggleClass('select_opened');
    thisSelect.closest('.filter__line').toggleClass('active');
  });

  select.on('click', '.select__option', function(event) {
    var thisSelect = $(this).closest('.select');
    var selectedValue = ($(this).attr('value')) ? $(this).attr('value') : $(this).data('value');
    var label;

    if (thisSelect.hasClass('select_checkbox')) {
      return;
    }

    if (thisSelect.hasClass('with_sort_direction')){
      label = $(this).html()
    }
    else{
      sliceLength = $(this).html().indexOf('<span>')
      if (sliceLength > 0){
        label = $(this).html().slice(0, sliceLength).trim();
      }else{
        label = $(this).html()
      }
    }
    thisSelect.find('select').val('');
    thisSelect.find('select').val(selectedValue);

    var selectId = thisSelect.attr('id');

    if (($(window).innerWidth() <= GLOBAL_CONSTANTS.mobile_width) && (selectId) && (selectId.split('_')[0] == 'sort')) {
      thisSelect.find('.select__input').html("&uarr;&darr;");
    } else {
      thisSelect.find('.select__input').html(label);
    }

    thisSelect.find('.select__input').data('selected', selectedValue);
    thisSelect.removeClass('select_opened');
    selected.detail.elem = this;
    selected.detail.value = $(this).data('value');
    thisSelect[0].dispatchEvent(selected);

    if (!thisSelect.hasClass('select_sort')) {
      catalogSetAllFieldsByValue(thisSelect, selectedValue);
    }

    // Remove hover effect
    thisSelect.hide().show();
  });

  select.on('change', '.checkbox__input', function() {
    var thisSelect = $(this).closest('.select');
    var hiddenSelect = thisSelect.find('.select__hidden').prop('name');
    var selectName = (hiddenSelect) ? hiddenSelect.split('_')[0] : '';

    selectName = (selectName == 'dealers') ? 'салон' : 'город';

    var checked = thisSelect.find('.checkbox__input').filter(':checked').length;

    if (checked === 0 || checked === thisSelect.find('.checkbox__input').length) {
      label = (selectName == 'город') ? "Все города" : "Все салоны";
    } else if (checked % 10 === 1) {
      label = "1 " + selectName;
    } else if (checked % 10 < 5) {
      label = checked + ' ' + selectName + 'а';
    } else {
      label = checked + ' ' + selectName + "ов";
    }

    thisSelect.find('.select__input').text(label);
  })


  $('.form_brands').on('selected', function() {
    var model = $('#models');
    if (model.length == 0) model = $(this).parent().next().find(".form_models");

    model.removeClass('select_disabled');
    model.find('.select__input').text('Выберите');

    var val = $(this).find('select').val();
    var url = "/car_brands/"+val+"/car_models";
    $.ajax({
      url: url,
      dataType: 'json',
      success: function(data) {
        var options = model.find('.select__options');
        var li = [];
        li = data.map(function(m) {
          return $('<li>').addClass('select__option').attr('data-value', m[0]).html(m[1] + " ");
        });
        options.html(li);

        if (model.find('.form_models')) {
          options = model.find('.select__hidden');
          options.removeAttr('disabled');
          options.removeClass('select_disabled');
          li = data.map(function(m) {
            return $('<option>').attr('value', m[0]).html(m[1]);
          });
          options.html([$('<option></option>')].concat(li));
        }
      }
    });
  })

  $('.form_models').on('selected', function() {
    var button = $('#search-submit');

    button.prop('disabled', false);
  })

  $('#brands').on('selected', function() {
    var model = $('#models');

    model.removeClass('select_disabled');
    $(".search-form__btn.btn").removeAttr('disabled');
    // model.find('.select__input').text('Сначала укажите марку');
  })

  $('#models').on('selected', function() {
    var button = $('#search-submit');

    button.prop('disabled', false);
  })

  $(window).on('scroll touchmove', function(e) {
    if($(window).innerWidth() <= GLOBAL_CONSTANTS.mobile_width){
      if($('#brands.select_opened').length || $('#models.select_opened').length){
        $('body').addClass('stop-scroll');
        e.preventDefault();
      } else {
        $('body').removeClass('stop-scroll');
      }
    }
  });
}

$(document).on('change', '.select__hidden', function(event) {
  var selectedOption = $(this).find('option:selected');
  var selectValue = selectedOption.attr('value');
  var sortDirection = selectedOption.attr('direction');

  $(this).find("option[value='" + selectValue + "']").attr('selected', 'selected');
  $(this).next().find('.select__input').first().attr('data-selected', selectValue);

  var selectOptions = $(this).next().find('.select__options');
  var attributeName = (['vehicle_model', 'car_generation_id'].includes($(this).attr('name'))) ? 'value' : 'data-value';

  if (sortDirection) {
    selectOptions.find("[" + attributeName + "='" + selectValue + "'][data-direction='" + sortDirection + "']").click();
  } else {
    selectOptions.find("[" + attributeName + "='" + selectValue + "']").click();
  }
});

function initAccordeon() {
  var clicked = false;

  $('.js-accordeon').on('mousedown', function() {
    clicked = true;
    if ($(this).hasClass('js-accordeon_opened')) {
      disableAcc();
      return;
    }

    disableAcc();
    enableAcc($(this));
  })

  $('.js-accordeon').on('focus', function() {
    if (clicked === true) {
      clicked = false;
      return;
    }

    if ($(this).hasClass('js-accordeon_opened')) {
      disableAcc();
      return;
    }

    disableAcc();
    enableAcc($(this));
  })

  $('.sitemap-menu__item').on('focus', 'a', function() {
    disableAcc();
    enableAcc($(this).parents('.sitemap-menu').find('.js-accordeon'));
  })

  function enableAcc(acc) {
    acc.addClass('js-accordeon_opened');
    acc.find('.ac-icon').addClass('ac-icon_active');
  }

  function disableAcc() {
    $('.js-accordeon_opened').removeClass('js-accordeon_opened');
    $('.ac-icon_active').removeClass('ac-icon_active');
  }
}

function initMobileToggle() {
  $('.mobile-toggle').on('click', function() {
    $(this).toggleClass('mobile-toggle_active');
    $('.js-mobile__wrapper').toggleClass('js-mobile_opened');
    $('.mobile-nav').toggleClass('mobile-nav_opened');
    $('body').toggleClass('js-mobile_opened');

    $('body').on('keydown', function(event) {
      if (event.keyCode==9 && $(this).hasClass('js-mobile_opened')) {
        event.preventDefault;
        return false;
      }
    });

  })

  $('.mobile-nav').swipe({
    allowPageScroll:"auto",
    swipe:function(event, direction, distance, duration, fingerCount, fingerData) {
      if($('body').hasClass('js-mobile_opened') && direction == "left"){
        $('.mobile-toggle').click();
        $('.js-burger-menu').removeClass('is-open')
        $('.js-dropdown-menu-overlay').removeClass('is-open')
        $('.js-f-mobile-menu-expandable').removeClass('is-open')
        document.body.classList.remove('js-mobile_opened')
      }
    }
  });

  $('.mobile-nav__close').on('click', function(event) {
    if ($('.mobile-nav').hasClass('mobile-nav_opened')) {
      $('.mobile-toggle').removeClass('mobile-toggle_active');
      $('.js-mobile__wrapper').removeClass('js-mobile_opened');
      $(".mobile-nav").removeClass('mobile-nav_opened');
      $('body.js-mobile_opened').removeClass('js-mobile_opened');
    }
  })
}

function initCollapse() {
  $('[data-toggle="collapse"]').on('click', function() {
    var target = $(this).data('target');
    $(target).css('overflow', 'hidden');

    if ($(target).hasClass('is-collapsed')) {
      setTimeout(function() {
        $(target).css('overflow', 'visible');
      }, 200);
    } else {
      $(target).css('overflow', 'hidden');
    }

    $(target).toggleClass('is-collapsed');
  })
}

function initMobileFilterDirection() {
  if ($(window).innerWidth() <= GLOBAL_CONSTANTS.mobile_width) {
    if ($("#sort_type")) {
      $("#sort_type").find('.select__input').html("&uarr;&darr;");
    }
  }
}

function initMap () {
  myGeoObjects = [];
  const map = new ymaps.Map('map', {
    center: [51.51, 40.51],
    zoom: 5,
    controls: ['fullscreenControl', 'zoomControl'],
  })

  map.behaviors.disable('scrollZoom');

  const dealers = $('#map').data('dealers')

  const clusterer = new ymaps.Clusterer({
    clusterIconColor: '#003DFF',
    zoomMargin: 100,
  })

  $.each(dealers, function(index, dealer) {
    placeMarkers(dealer, map, clusterer)
  })
}

function initSmallMap() {
  myGeoObjects = [];
  var dealers = $('#smallMap').data('dealers');

  var centerLatitude = (dealers[0].latitude) ? dealers[0].latitude : 51.51;
  var centerLongitude = (dealers[0].longitude) ? dealers[0].longitude : 40.51;

  var map = new ymaps.Map('smallMap', {
    center: [centerLatitude, centerLongitude],
    zoom: 16,
    controls: ['fullscreenControl', 'zoomControl']
  });

  var clusterer = new ymaps.Clusterer(  {
    clusterIconColor: '#003DFF',
    zoomMargin: 100
  } );

  $.each(dealers, function(index, dealer) {
    placeMarkers(dealer, map, clusterer, { balloon: false });
  });
}

function placeMarkers(obj, map, clusterer, options) {
  options = Object.assign({}, {balloon: true}, options || {});
  var active_marker;

  var MyBalloonLayout = ymaps.templateLayoutFactory.createClass('<div class="balloon"><div class="balloon__layout"><div class="balloon__content">$[[options.contentLayout observeSize]]</div><div class="balloon__close"></div><div class="balloon__tail"></div></div></div>') ;

  var HintLayout = ymaps.templateLayoutFactory.createClass(
    '<div class="map-hint">' +
    '<div class="visual">'+
    '<img src="$[properties.dealer_img]" alt="">'+
    '<p class="map-hint__title">$[properties.title]</p>' +
    '</div>'+
    '<div class="marker__text">'+
    '<a href="$[properties.link]">' +
    '<p class="map-hint__address">$[properties.title]</p>' +
    '<p class="map-hint__phone">$[properties.phone]</p>' +
    '<div class="map-hint__dealer">'+
    '<span>Офиц. дилер</span>'+
    '<ul>'+
    '$[properties.dealers]' +
    "</ul>"+
    '</div>' +
    '</a>' +
    '</div>'+
    '</div>');

  var coords = [obj.latitude, obj.longitude];

  var title = obj.title;

  var balloonOptions = {};

  if(options.balloon) {
    balloonOptions = {
      balloonOffset: [0, -32],
      balloonLayout: MyBalloonLayout,
      balloonContentLayout: HintLayout,
      hideIconOnBalloonOpen: false
    };
  }

  placemark = new ymaps.Placemark(coords, {
    title: title,
    map_address: obj.address,
    phone: obj.phone,
    link: obj.link,
    dealer_img: obj.dealer_img,
    dealers: obj.dealers,
    coord: coords,
  }, Object.assign({}, {
    // hasHint: false,
    iconLayout: 'default#image',
    iconImageClipRect: [[0,0], [39, 34]],
    iconImageHref: '/marker.svg',
    iconImageSize: [39, 34],
    iconImageOffset: [-13, -34],
  }, balloonOptions));

  if(options.balloon) {
    placemark.events.add('click', function (e) {
      if ($(window).innerWidth() <= GLOBAL_CONSTANTS.mobile_width) {
        e.preventDefault();
        $('.location-modal .map-hint .visual img').attr('src', obj.dealer_img);
        $('.location-modal .map-hint__title').text(obj.title);
        $('.location-modal .map-hint__address').text(obj.address);
        $('.location-modal .map-hint .marker__text a').attr('href', obj.link);
        $('.location-modal__btn-panel .more').attr('href', obj.link);
        $('body').addClass('location-modal-open');
      }
      var coords = e.get('coords');
      map.setCenter([coords[0], coords[1]]);
    });
  }

  myGeoObjects.push(placemark);
  map.geoObjects.add(placemark);
  if(options.balloon) {
    map.events.add('balloonopen', function (e) {
      var balloon = e.get('balloon');
      map.events.add('click', function (e) {
        if (e.get('target') === map) {
          map.balloon.close();
        }
      });
    });
  }

  clusterer.add(myGeoObjects);
  map.geoObjects.add(clusterer);

  $('.location-modal .bg, .location-modal .close-btn-holder .close-btn').on('click', function(e) {
    e.preventDefault();
    $('body').removeClass('location-modal-open');
  });
}

var initPhotoSwipeFromDOM = function(gallerySelector) {
  // parse slide data (url, title, size ...) from DOM elements
  // (children of gallerySelector)
  var parseThumbnailElements = function(el) {
    var thumbElements = el.childNodes,
      numNodes = thumbElements.length,
      items = [],
      figureEl,
      linkEl,
      size,
      item,
      mainClass = 'pswp--minimal--dark';


    for(var i = 0; i < numNodes; i++) {

      figureEl = thumbElements[i]; // <figure> element

      // include only element nodes
      if(figureEl.nodeType !== 1) {
        continue;
      }

      linkEl = figureEl.children[0]; // <a> element

      size = linkEl.getAttribute('data-size').split('x');

      // create slide object
      item = {
        src: linkEl.getAttribute('href'),
        w: parseInt(size[0], 10),
        h: parseInt(size[1], 10)
      };



      if(figureEl.children.length > 1) {
        // <figcaption> content
        item.title = figureEl.children[1].innerHTML;
      }

      if(linkEl.children.length > 0) {
        // <img> thumbnail element, retrieving thumbnail url
        item.msrc = linkEl.children[0].getAttribute('src');
      }

      item.el = figureEl; // save link to element for getThumbBoundsFn
      items.push(item);
    }

    return items;
  };

  // find nearest parent element
  var closest = function closest(el, fn) {
    return el && ( fn(el) ? el : closest(el.parentNode, fn) );
  };

  // triggers when user clicks on thumbnail
  var onThumbnailsClick = function(e) {
    e = e || window.event;
    e.preventDefault ? e.preventDefault() : e.returnValue = false;

    var eTarget = e.target || e.srcElement;

    // find root element of slide
    var clickedListItem = closest(eTarget, function(el) {
      return (el.tagName && el.tagName.toUpperCase() === 'DIV');
    });

    if(!clickedListItem) {
      return;
    }

    // find index of clicked item by looping through all child nodes
    // alternatively, you may define index via data- attribute
    var clickedGallery = clickedListItem.parentNode,
      childNodes = clickedListItem.parentNode.childNodes,
      numChildNodes = childNodes.length,
      nodeIndex = 0,
      index;

    for (var i = 0; i < numChildNodes; i++) {
      if(childNodes[i].nodeType !== 1) {
        continue;
      }

      if(childNodes[i] === clickedListItem) {
        index = nodeIndex;
        break;
      }
      nodeIndex++;
    }

    if(index >= 0) {
      // open PhotoSwipe if valid index found
      openPhotoSwipe( index, clickedGallery );
    }
    return false;
  };

  // parse picture index and gallery index from URL (#&pid=1&gid=2)
  var photoswipeParseHash = function() {
    var hash = window.location.hash.substring(1),
      params = {};

    if(hash.length < 5) {
      return params;
    }

    var vars = hash.split('&');
    for (var i = 0; i < vars.length; i++) {
      if(!vars[i]) {
        continue;
      }
      var pair = vars[i].split('=');
      if(pair.length < 2) {
        continue;
      }
      params[pair[0]] = pair[1];
    }

    if(params.gid) {
      params.gid = parseInt(params.gid, 10);
    }

    return params;
  };

  var openPhotoSwipe = function(index, galleryElement, disableAnimation, fromURL) {
    var pswpElement = document.querySelectorAll('.pswp')[0],
      gallery,
      options,
      items;

    items = parseThumbnailElements(galleryElement);

    // define options (if needed)
    options = {

      // define gallery index (for URL)
      galleryUID: galleryElement.getAttribute('data-pswp-uid'),

      getThumbBoundsFn: function(index) {
        // See Options -> getThumbBoundsFn section of documentation for more info
        var thumbnail = items[index].el.getElementsByTagName('img')[0], // find thumbnail
          pageYScroll = window.pageYOffset || document.documentElement.scrollTop,
          rect = thumbnail.getBoundingClientRect();

        return {x:rect.left, y:rect.top + pageYScroll, w:rect.width};
      }

    };

    // PhotoSwipe opened from URL
    if(fromURL) {
      if(options.galleryPIDs) {
        // parse real index when custom PIDs are used
        // http://photoswipe.com/documentation/faq.html#custom-pid-in-url
        for(var j = 0; j < items.length; j++) {
          if(items[j].pid == index) {
            options.index = j;
            break;
          }
        }
      } else {
        // in URL indexes start from 1
        options.index = parseInt(index, 10) - 1;
      }
    } else {
      options.index = parseInt(index, 10);
    }

    // exit if index not found
    if( isNaN(options.index) ) {
      return;
    }

    if(disableAnimation) {
      options.showAnimationDuration = 0;
    }

    // Pass data to PhotoSwipe and initialize it
    gallery = new PhotoSwipe( pswpElement, PhotoSwipeUI_Default, items, options);
    gallery.init();
  };

  // loop through all gallery elements and bind events
  var galleryElements = document.querySelectorAll( gallerySelector );

  for(var i = 0, l = galleryElements.length; i < l; i++) {
    galleryElements[i].setAttribute('data-pswp-uid', i+1);
    galleryElements[i].onclick = onThumbnailsClick;
  }

  // Parse URL and open gallery if it contains #&pid=3&gid=1
  var hashData = photoswipeParseHash();
  if(hashData.pid && hashData.gid) {
    openPhotoSwipe( hashData.pid ,  galleryElements[ hashData.gid - 1 ], true, true );
  }
};

