/**
 * Получает значение указанной куки.
 * @param {string} name - Имя куки.
 * @returns {string|undefined} Значение куки или undefined, если кука не найдена.
 */
function getCookie(name) {
  let matches = document.cookie.match(
    new RegExp(
      '(?:^|; )' + name.replace(/([\.$?*|{}\(\)\[\]\\\/\+^])/g, '\\$1') + '=([^;]*)'
    )
  );
  return matches ? decodeURIComponent(matches[1]) : undefined;
}

/**
 * Устанавливает куку с указанным именем, значением и сроком действия.
 * @param {string} name - Имя куки.
 * @param {string} value - Значение куки.
 * @param {number} days - Количество дней до истечения срока действия куки.
 */
function setCookie(name, value, days) {
  let expires = "";
  if (days) {
    let date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    expires = "; expires=" + date.toUTCString();
  }
  document.cookie = name + "=" + (value || "") + expires + "; path=/; SameSite=Lax";
}

/**
 * Удаляет куку, устанавливая ее срок действия на прошедшую дату.
 * @param {string} name - Имя куки, которую нужно удалить.
 */
function deleteCookie(name) {
  setCookie(name, '', -1);
};
